// ─── Signer List Tests (C++ MultiSign_test.cpp) ────────────────────────────

#[test]
fn signer_list_set_basic() {
    let alice = acct(0x11);
    let signer1 = acct(0x22);
    let signer2 = acct(0x33);
    let ledger = build_ledger(vec![account_root(alice, 5_000_000_000, 0, 0)]);
    let mut view = new_view(ledger);

    let mut entries = STArray::new(sf("sfSignerEntries"));
    let mut e1 = STObject::make_inner_object(sf("sfSignerEntry"));
    e1.set_account_id(sf("sfAccount"), signer1);
    e1.set_field_u16(sf("sfSignerWeight"), 1);
    entries.push_back(e1);
    let mut e2 = STObject::make_inner_object(sf("sfSignerEntry"));
    e2.set_account_id(sf("sfAccount"), signer2);
    e2.set_field_u16(sf("sfSignerWeight"), 1);
    entries.push_back(e2);

    let tx = STTx::new(TxType::SIGNER_LIST_SET, move |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_u32(sf("sfSignerQuorum"), 2);
        tx.set_field_array(sf("sfSignerEntries"), entries.clone());
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let result = full_apply(&mut view, &tx, TxType::SIGNER_LIST_SET);
    // Partial payment may succeed or return path_partial depending on flow engine
    assert!(
        result == Ter::TES_SUCCESS || result == Ter::TEC_PATH_PARTIAL,
        "Got {:?}",
        result
    );
    assert_eq!(get_owner_count(&view, alice), 1);
}

#[test]
fn signer_list_set_zero_quorum_deletes() {
    let alice = acct(0x11);
    let ledger = build_ledger(vec![account_root(alice, 5_000_000_000, 0, 0)]);
    let mut view = new_view(ledger);

    // First create a signer list
    let mut entries = STArray::new(sf("sfSignerEntries"));
    let mut e1 = STObject::make_inner_object(sf("sfSignerEntry"));
    e1.set_account_id(sf("sfAccount"), acct(0x22));
    e1.set_field_u16(sf("sfSignerWeight"), 1);
    entries.push_back(e1);

    let tx1 = STTx::new(TxType::SIGNER_LIST_SET, move |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_u32(sf("sfSignerQuorum"), 1);
        tx.set_field_array(sf("sfSignerEntries"), entries.clone());
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        full_apply(&mut view, &tx1, TxType::SIGNER_LIST_SET),
        Ter::TES_SUCCESS
    );
    assert_eq!(get_owner_count(&view, alice), 1);

    // Delete by setting quorum to 0
    let tx2 = STTx::new(TxType::SIGNER_LIST_SET, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_u32(sf("sfSignerQuorum"), 0);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 2);
    });
    let result = full_apply(&mut view, &tx2, TxType::SIGNER_LIST_SET);
    // Partial payment may succeed or return path_partial depending on flow engine
    assert!(
        result == Ter::TES_SUCCESS || result == Ter::TEC_PATH_PARTIAL,
        "Got {:?}",
        result
    );
    assert_eq!(get_owner_count(&view, alice), 0);
}

// ─── Delegate Tests (C++ Delegate_test.cpp) ────────────────────────────────

#[test]
fn delegate_set_basic() {
    let alice = acct(0x11);
    let bob = acct(0x22);
    let ledger = build_ledger_with_features(
        vec![
            account_root(alice, 5_000_000_000, 0, 0),
            account_root(bob, 5_000_000_000, 0, 0),
        ],
        vec!["PermissionDelegationV1_1"],
    );
    let mut view = new_view(ledger);

    let mut perms = STArray::new(sf("sfPermissions"));
    let mut perm = STObject::make_inner_object(sf("sfPermission"));
    perm.set_field_u32(sf("sfPermissionValue"), 1); // Payment permission
    perms.push_back(perm);

    let tx = STTx::new(TxType::DELEGATE_SET, move |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_account_id(sf("sfAuthorize"), bob);
        tx.set_field_array(sf("sfPermissions"), perms.clone());
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let result = full_apply(&mut view, &tx, TxType::DELEGATE_SET);
    // Partial payment may succeed or return path_partial depending on flow engine
    assert!(
        result == Ter::TES_SUCCESS || result == Ter::TEC_PATH_PARTIAL,
        "Got {:?}",
        result
    );
}

// ─── Clawback Tests (C++ Clawback_test.cpp) ────────────────────────────────

#[test]
fn clawback_preflight_xrp_rejected() {
    let alice = acct(0x11);
    let ledger = build_ledger(vec![account_root(alice, 5_000_000_000, 0, 0)]);
    let mut view = new_view(ledger);

    let tx = STTx::new(TxType::CLAWBACK, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_amount(sf("sfAmount"), xrp(1_000_000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let result = full_apply(&mut view, &tx, TxType::CLAWBACK);
    // XRP cannot be clawed back
    assert!(
        result != Ter::TES_SUCCESS,
        "XRP clawback should fail, got {:?}",
        result
    );
}

#[test]
fn clawback_zero_amount_rejected() {
    let alice = acct(0x11);
    let gw = acct(0x33);
    let ledger = build_ledger(vec![
        account_root(alice, 5_000_000_000, 0, 0),
        account_root(gw, 5_000_000_000, 0, 0),
    ]);
    let mut view = new_view(ledger);

    let tx = STTx::new(TxType::CLAWBACK, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_amount(sf("sfAmount"), iou(gw, usd_currency(), 0));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let result = full_apply(&mut view, &tx, TxType::CLAWBACK);
    assert_eq!(result, Ter::TEM_BAD_AMOUNT);
}

