#[test]
fn mptoken_issuance_destroy_nonexistent() {
    let alice = acct(0x11);
    let ledger = build_ledger(vec![account_root(alice, 5_000_000_000, 0, 0)]);
    let mut view = new_view(ledger);
    let tx = STTx::new(TxType::MPTOKEN_ISSUANCE_DESTROY, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_h192(
            sf("sfMPTokenIssuanceID"),
            basics::base_uint::Uint192::from_array([0xBB; 24]),
        );
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    // Fixed: no longer panics — returns TEC_OBJECT_NOT_FOUND or TES_SUCCESS
    let result = handle_real_dispatch(&mut view, &tx, TxType::MPTOKEN_ISSUANCE_DESTROY, None);
    assert!(
        result == Ter::TEC_OBJECT_NOT_FOUND || result == Ter::TES_SUCCESS,
        "Got {:?}",
        result
    );
}

#[test]
fn mptoken_authorize_nonexistent() {
    let alice = acct(0x11);
    let ledger = build_ledger(vec![account_root(alice, 5_000_000_000, 0, 0)]);
    let mut view = new_view(ledger);
    let tx = STTx::new(TxType::MPTOKEN_AUTHORIZE, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_h192(
            sf("sfMPTokenIssuanceID"),
            basics::base_uint::Uint192::from_array([0xCC; 24]),
        );
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let result = handle_real_dispatch(&mut view, &tx, TxType::MPTOKEN_AUTHORIZE, None);
    assert!(
        result == Ter::TEC_OBJECT_NOT_FOUND
            || result == Ter::TEC_NO_ENTRY
            || result == Ter::TES_SUCCESS,
        "Got {:?}",
        result
    );
}

