#[test]
fn freeze_set_on_trust_line() {
    let alice = acct(0x11);
    let gw = acct(0x33);
    let usd = usd_currency();
    let ledger = build_ledger(vec![
        account_root(alice, 5_000_000_000, 1, 0),
        account_root(gw, 5_000_000_000, 0, 0),
        trust_line(alice, gw, usd, 1000, 10000, 0),
    ]);
    let mut view = new_view(ledger);

    // gw freezes alice's trust line (tfSetFreeze = 0x00100000)
    let tx = STTx::new(TxType::TRUST_SET, |tx| {
        tx.set_account_id(sf("sfAccount"), gw);
        let cur = protocol::currency_from_string("USD");
        let issue = Issue::new(cur, alice);
        tx.set_field_amount(
            sf("sfLimitAmount"),
            STAmount::from_iou_amount(sf_generic(), IOUAmount::from_parts(0, 0).expect("a"), issue),
        );
        tx.set_field_u32(sf("sfFlags"), 0x00100000); // tfSetFreeze
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let result = full_apply(&mut view, &tx, TxType::TRUST_SET);
    // Partial payment may succeed or return path_partial depending on flow engine
    assert!(
        result == Ter::TES_SUCCESS || result == Ter::TEC_PATH_PARTIAL,
        "Got {:?}",
        result
    );
}

#[test]
fn freeze_global_set_via_account_set() {
    let gw = acct(0x33);
    let ledger = build_ledger(vec![account_root(gw, 5_000_000_000, 0, 0)]);
    let mut view = new_view(ledger);

    // Set global freeze via AccountSet (asfGlobalFreeze = 7)
    let tx = STTx::new(TxType::ACCOUNT_SET, |tx| {
        tx.set_account_id(sf("sfAccount"), gw);
        tx.set_field_u32(sf("sfSetFlag"), 7); // asfGlobalFreeze
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let result = full_apply(&mut view, &tx, TxType::ACCOUNT_SET);
    // Partial payment may succeed or return path_partial depending on flow engine
    assert!(
        result == Ter::TES_SUCCESS || result == Ter::TEC_PATH_PARTIAL,
        "Got {:?}",
        result
    );

    // Verify the flag was set
    let gw_sle = view.read(account_keylet(acct_id(gw))).unwrap().unwrap();
    let flags = gw_sle.get_field_u32(sf("sfFlags"));
    assert!(
        (flags & 0x00400000) != 0,
        "lsfGlobalFreeze should be set, flags={:#x}",
        flags
    );
}

