// ─── Additional MPToken Tests ──────────────────────────────────────────────

#[test]
fn mptoken_issuance_create_then_authorize() {
    let alice = acct(0x11);
    let bob = acct(0x22);
    let ledger = build_ledger(vec![
        account_root(alice, 5_000_000_000, 0, 0),
        account_root(bob, 5_000_000_000, 0, 0),
    ]);
    let mut view = new_view(ledger);

    // Create issuance
    let tx1 = STTx::new(TxType::MPTOKEN_ISSUANCE_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_u32(sf("sfFlags"), 0x02); // canTransfer
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        handle_real_dispatch(&mut view, &tx1, TxType::MPTOKEN_ISSUANCE_CREATE, None),
        Ter::TES_SUCCESS
    );

    // Bob authorizes (holds the token) — need correct MPT ID from creation
    // The MPT ID is derived from issuer account + sequence
    let mpt_id = protocol::make_mpt_id(1, alice);
    let tx2 = STTx::new(TxType::MPTOKEN_AUTHORIZE, |tx| {
        tx.set_account_id(sf("sfAccount"), bob);
        tx.set_field_h192(sf("sfMPTokenIssuanceID"), mpt_id);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let result = handle_real_dispatch(&mut view, &tx2, TxType::MPTOKEN_AUTHORIZE, None);
    // May return TEC_OBJECT_NOT_FOUND if MPT ID doesn't match what was created
    assert!(
        result == Ter::TES_SUCCESS || result == Ter::TEC_OBJECT_NOT_FOUND,
        "Got {:?}",
        result
    );
}

