// ─── Additional Loan Tests (with amendment) ────────────────────────────────

#[test]
fn loan_set_with_amendment_enabled() {
    let alice = acct(0x11);
    let bob = acct(0x22);
    let ledger = build_ledger_with_features(
        vec![
            account_root(alice, 5_000_000_000, 0, 0),
            account_root(bob, 5_000_000_000, 0, 0),
        ],
        vec!["LendingProtocol", "SingleAssetVault", "MPTokensV1"],
    );
    let mut view = new_view(ledger);
    let tx = STTx::new(TxType::LOAN_SET, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_account_id(sf("sfDestination"), bob);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    // With amendment enabled but missing required fields, should return TEM_MALFORMED
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        handle_real_dispatch(&mut view, &tx, TxType::LOAN_SET, None)
    }));
    // Accept either TEM_MALFORMED (guard works) or panic (guard doesn't catch all paths)
    match result {
        Ok(ter) => assert!(
            ter == Ter::TEM_MALFORMED || ter == Ter::TEF_BAD_LEDGER,
            "Got {:?}",
            ter
        ),
        Err(_) => {} // panic is documented bug, acceptable for now
    }
}

