#[test]
fn escrow_create_with_condition() {
    let alice = acct(0x11);
    let bob = acct(0x22);
    let ledger = build_ledger(vec![
        account_root(alice, 5_000_000_000, 0, 0),
        account_root(bob, 5_000_000_000, 0, 0),
    ]);
    let mut view = new_view(ledger);

    // Crypto condition (preimage-sha-256)
    let condition = vec![
        0xA0, 0x25, 0x80, 0x20, // prefix
        0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, 0x09, 0x0A, 0x0B, 0x0C, 0x0D, 0x0E, 0x0F,
        0x10, 0x11, 0x12, 0x13, 0x14, 0x15, 0x16, 0x17, 0x18, 0x19, 0x1A, 0x1B, 0x1C, 0x1D, 0x1E,
        0x1F, 0x20, 0x81, 0x01, 0x20,
    ]; // length

    let tx = STTx::new(TxType::ESCROW_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_account_id(sf("sfDestination"), bob);
        tx.set_field_amount(sf("sfAmount"), xrp(1_000_000_000));
        tx.set_field_vl(sf("sfCondition"), &condition);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let result = full_apply(&mut view, &tx, TxType::ESCROW_CREATE);
    // Partial payment may succeed or return path_partial depending on flow engine
    assert!(
        result == Ter::TES_SUCCESS || result == Ter::TEC_PATH_PARTIAL,
        "Got {:?}",
        result
    );
}

