#[test]
fn credential_create_then_accept() {
    let alice = acct(0x11); // issuer
    let bob = acct(0x22); // subject
    let ledger = build_ledger(vec![
        account_root(alice, 5_000_000_000, 0, 0),
        account_root(bob, 5_000_000_000, 0, 0),
    ]);
    let mut view = new_view(ledger);

    // Create credential
    let tx1 = STTx::new(TxType::CREDENTIAL_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_account_id(sf("sfSubject"), bob);
        tx.set_field_vl(sf("sfCredentialType"), b"KYC");
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        handle_real_dispatch(&mut view, &tx1, TxType::CREDENTIAL_CREATE, None),
        Ter::TES_SUCCESS
    );

    // Accept credential
    let tx2 = STTx::new(TxType::CREDENTIAL_ACCEPT, |tx| {
        tx.set_account_id(sf("sfAccount"), bob);
        tx.set_account_id(sf("sfIssuer"), alice);
        tx.set_field_vl(sf("sfCredentialType"), b"KYC");
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let result = handle_real_dispatch(&mut view, &tx2, TxType::CREDENTIAL_ACCEPT, None);
    // Partial payment may succeed or return path_partial depending on flow engine
    assert!(
        result == Ter::TES_SUCCESS || result == Ter::TEC_PATH_PARTIAL,
        "Got {:?}",
        result
    );
}

