#[test]
fn account_set_clear_flag() {
    let alice = acct(0x11);
    // Start with RequireDest set
    let lsf_require_dest: u32 = 0x00020000;
    let ledger = build_ledger(vec![account_root(
        alice,
        5_000_000_000,
        0,
        lsf_require_dest,
    )]);
    let mut view = new_view(ledger);

    // Clear asfRequireDest (1)
    let tx = STTx::new(TxType::ACCOUNT_SET, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_u32(sf("sfClearFlag"), 1);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let result = full_apply(&mut view, &tx, TxType::ACCOUNT_SET);
    // Partial payment may succeed or return path_partial depending on flow engine
    assert!(
        result == Ter::TES_SUCCESS || result == Ter::TEC_PATH_PARTIAL,
        "Got {:?}",
        result
    );

    // Verify flag was cleared
    let sle = view.read(account_keylet(acct_id(alice))).unwrap().unwrap();
    let flags = sle.get_field_u32(sf("sfFlags"));
    assert_eq!(flags & lsf_require_dest, 0, "RequireDest should be cleared");
}

