// ─── Freeze Tests (C++ Freeze_test.cpp) ────────────────────────────────────

#[test]
fn freeze_set_and_clear_on_trust_line() {
    let alice = acct(0x11);
    let gw = acct(0x33);
    let usd = usd_currency();
    let ledger = build_ledger(vec![
        account_root(alice, 5_000_000_000, 1, 0),
        account_root(gw, 5_000_000_000, 0, 0),
        trust_line(alice, gw, usd, 1000, 10000, 0),
    ]);
    let mut view = new_view(ledger);

    // Set freeze (tfSetFreeze = 0x00100000)
    let tx1 = STTx::new(TxType::TRUST_SET, |tx| {
        tx.set_account_id(sf("sfAccount"), gw);
        let issue = Issue::new(usd, alice);
        tx.set_field_amount(
            sf("sfLimitAmount"),
            STAmount::from_iou_amount(sf_generic(), IOUAmount::from_parts(0, 0).expect("a"), issue),
        );
        tx.set_field_u32(sf("sfFlags"), 0x00100000);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        full_apply(&mut view, &tx1, TxType::TRUST_SET),
        Ter::TES_SUCCESS
    );

    // Verify alice can't sell USD (frozen)
    let tx2 = STTx::new(TxType::OFFER_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_amount(sf("sfTakerPays"), xrp(1_000_000_000));
        tx.set_field_amount(sf("sfTakerGets"), iou(gw, usd, 1000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let result = handle_real_dispatch(&mut view, &tx2, TxType::OFFER_CREATE, None);
    assert_eq!(result, Ter::TEC_UNFUNDED_OFFER);
}

