#[test]
fn offer_create_two_accounts_different_ious() {
    let alice = acct(0x11);
    let bob = acct(0x22);
    let gw = acct(0x33);
    let usd = usd_currency();
    let eur = eur_currency();
    let ledger = build_ledger(vec![
        account_root(alice, 10_000_000_000, 2, 0),
        account_root(bob, 10_000_000_000, 2, 0),
        account_root(gw, 10_000_000_000, 0, 0),
        trust_line(alice, gw, usd, 1000, 10000, 0),
        trust_line(alice, gw, eur, 0, 10000, 0),
        trust_line(bob, gw, usd, 0, 10000, 0),
        trust_line(bob, gw, eur, 1000, 10000, 0),
    ]);
    let mut view = new_view(ledger);

    // Alice: sell USD, buy EUR
    let tx1 = STTx::new(TxType::OFFER_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_amount(sf("sfTakerPays"), iou(gw, eur, 500));
        tx.set_field_amount(sf("sfTakerGets"), iou(gw, usd, 500));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        handle_real_dispatch(&mut view, &tx1, TxType::OFFER_CREATE, None),
        Ter::TES_SUCCESS
    );

    // Bob: sell EUR, buy USD — should cross
    let tx2 = STTx::new(TxType::OFFER_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), bob);
        tx.set_field_amount(sf("sfTakerPays"), iou(gw, usd, 500));
        tx.set_field_amount(sf("sfTakerGets"), iou(gw, eur, 500));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let r2 = handle_real_dispatch(&mut view, &tx2, TxType::OFFER_CREATE, None);
    assert_eq!(r2, Ter::TES_SUCCESS);
}

#[test]
fn offer_cancel_by_different_account_fails() {
    let alice = acct(0x11);
    let bob = acct(0x22);
    let gw = acct(0x33);
    let usd = usd_currency();
    let ledger = build_ledger(vec![
        account_root(alice, 10_000_000_000, 1, 0),
        account_root(bob, 10_000_000_000, 0, 0),
        account_root(gw, 10_000_000_000, 0, 0),
        trust_line(alice, gw, usd, 1000, 10000, 0),
    ]);
    let mut view = new_view(ledger);

    // Alice creates offer
    let tx1 = STTx::new(TxType::OFFER_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_amount(sf("sfTakerPays"), xrp(1_000_000_000));
        tx.set_field_amount(sf("sfTakerGets"), iou(gw, usd, 1000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        handle_real_dispatch(&mut view, &tx1, TxType::OFFER_CREATE, None),
        Ter::TES_SUCCESS
    );

    // Bob tries to cancel alice's offer — should fail (different account)
    let tx2 = STTx::new(TxType::OFFER_CANCEL, |tx| {
        tx.set_account_id(sf("sfAccount"), bob);
        tx.set_field_u32(sf("sfOfferSequence"), 1);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let result = full_apply(&mut view, &tx2, TxType::OFFER_CANCEL);
    // Bob can only cancel his own offers — this is a no-op (offer not found for bob)
    // Partial payment may succeed or return path_partial depending on flow engine
    assert!(
        result == Ter::TES_SUCCESS || result == Ter::TEC_PATH_PARTIAL,
        "Got {:?}",
        result
    );
    // Alice's offer should still exist
    assert_eq!(get_owner_count(&view, alice), 2); // trust + offer
}

