#[test]
fn freeze_issuer_can_still_send_when_frozen() {
    let alice = acct(0x11);
    let gw = acct(0x33);
    let usd = usd_currency();
    let mut gw_root = account_root(gw, 5_000_000_000, 0, 0);
    gw_root.set_field_u32(sf("sfFlags"), 0x00400000); // global freeze
    let ledger = build_ledger(vec![
        account_root(alice, 5_000_000_000, 1, 0),
        gw_root,
        trust_line(alice, gw, usd, 0, 10000, 0),
    ]);
    let mut view = new_view(ledger);
    // Issuer can still send to holders even when globally frozen (C++ behavior)
    let tx = STTx::new(TxType::PAYMENT, |tx| {
        tx.set_account_id(sf("sfAccount"), gw);
        tx.set_account_id(sf("sfDestination"), alice);
        tx.set_field_amount(sf("sfAmount"), iou(gw, usd, 100));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let result = handle_real_dispatch(&mut view, &tx, TxType::PAYMENT, None);
    // Issuer sending their own tokens should work even when frozen
    assert!(
        result == Ter::TES_SUCCESS || result == Ter::TEC_PATH_DRY,
        "Issuer send got {:?}",
        result
    );
}

