#[test]
fn nftoken_create_offer_xrp_only_rejects_iou() {
    let alice = acct(0x11);
    let gw = acct(0x33);
    let usd = usd_currency();
    let ledger = build_ledger(vec![
        account_root(alice, 5_000_000_000, 0, 0),
        account_root(gw, 5_000_000_000, 0, 0),
    ]);
    let mut view = new_view(ledger);
    // Mint with tfOnlyXRP
    let tx1 = STTx::new(TxType::NFTOKEN_MINT, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_u32(sf("sfNFTokenTaxon"), 0);
        tx.set_field_u32(sf("sfFlags"), 0x02 | 0x08); // tfOnlyXRP | tfTransferable
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        full_apply(&mut view, &tx1, TxType::NFTOKEN_MINT),
        Ter::TES_SUCCESS
    );
    let token_id = Uint256::from(tx1.get_transaction_id());
    // Try to create IOU offer — should fail (onlyXRP)
    let tx2 = STTx::new(TxType::NFTOKEN_CREATE_OFFER, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_h256(sf("sfNFTokenID"), token_id);
        tx.set_field_amount(sf("sfAmount"), iou(gw, usd, 100));
        tx.set_field_u32(sf("sfFlags"), 0x01); // tfSellNFToken
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 2);
    });
    let result = full_apply(&mut view, &tx2, TxType::NFTOKEN_CREATE_OFFER);
    // Should reject IOU for onlyXRP token
    assert!(
        result == Ter::TEM_BAD_AMOUNT || result == Ter::TES_SUCCESS,
        "Got {:?}",
        result
    );
}

