#[test]
fn offer_cancel_all_offers() {
    let alice = acct(0x11);
    let gw = acct(0x33);
    let usd = usd_currency();
    let ledger = build_ledger(vec![
        account_root(alice, 10_000_000_000, 1, 0),
        account_root(gw, 10_000_000_000, 0, 0),
        trust_line(alice, gw, usd, 5000, 10000, 0),
    ]);
    let mut view = new_view(ledger);
    // Create 3 offers
    for i in 1..=3u32 {
        let tx = STTx::new(TxType::OFFER_CREATE, |tx| {
            tx.set_account_id(sf("sfAccount"), alice);
            tx.set_field_amount(sf("sfTakerPays"), xrp(100_000_000 * i as i64));
            tx.set_field_amount(sf("sfTakerGets"), iou(gw, usd, 100 * i as i64));
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), i);
        });
        assert_eq!(
            handle_real_dispatch(&mut view, &tx, TxType::OFFER_CREATE, None),
            Ter::TES_SUCCESS
        );
    }
    assert_eq!(get_owner_count(&view, alice), 4); // trust + 3 offers
    // Cancel all
    for i in 1..=3u32 {
        let tx = STTx::new(TxType::OFFER_CANCEL, |tx| {
            tx.set_account_id(sf("sfAccount"), alice);
            tx.set_field_u32(sf("sfOfferSequence"), i);
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), i + 3);
        });
        assert_eq!(
            full_apply(&mut view, &tx, TxType::OFFER_CANCEL),
            Ter::TES_SUCCESS
        );
    }
    assert_eq!(get_owner_count(&view, alice), 1); // just trust
}

