#[test]
fn signer_list_replace() {
    let alice = acct(0x11);
    let ledger = build_ledger(vec![account_root(alice, 5_000_000_000, 0, 0)]);
    let mut view = new_view(ledger);
    // Create with 2 signers
    let mut entries1 = STArray::new(sf("sfSignerEntries"));
    let mut e = STObject::make_inner_object(sf("sfSignerEntry"));
    e.set_account_id(sf("sfAccount"), acct(0x22));
    e.set_field_u16(sf("sfSignerWeight"), 1);
    entries1.push_back(e);
    let mut e2 = STObject::make_inner_object(sf("sfSignerEntry"));
    e2.set_account_id(sf("sfAccount"), acct(0x33));
    e2.set_field_u16(sf("sfSignerWeight"), 1);
    entries1.push_back(e2);
    let tx1 = STTx::new(TxType::SIGNER_LIST_SET, move |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_u32(sf("sfSignerQuorum"), 2);
        tx.set_field_array(sf("sfSignerEntries"), entries1.clone());
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        full_apply(&mut view, &tx1, TxType::SIGNER_LIST_SET),
        Ter::TES_SUCCESS
    );
    // Replace with 1 signer
    let mut entries2 = STArray::new(sf("sfSignerEntries"));
    let mut e3 = STObject::make_inner_object(sf("sfSignerEntry"));
    e3.set_account_id(sf("sfAccount"), acct(0x44));
    e3.set_field_u16(sf("sfSignerWeight"), 1);
    entries2.push_back(e3);
    let tx2 = STTx::new(TxType::SIGNER_LIST_SET, move |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_u32(sf("sfSignerQuorum"), 1);
        tx.set_field_array(sf("sfSignerEntries"), entries2.clone());
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 2);
    });
    assert_eq!(
        full_apply(&mut view, &tx2, TxType::SIGNER_LIST_SET),
        Ter::TES_SUCCESS
    );
}

