fn account_delete_balance_transferred() {
    let alice = acct(0x11);
    let bob = acct(0x22);
    let ledger = build_ledger(vec![
        account_root(alice, 5_000_000_000, 0, 0),
        account_root(bob, 1_000_000_000, 0, 0),
    ]);
    let mut view = new_view(ledger);
    let tx = STTx::new(TxType::ACCOUNT_DELETE, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_account_id(sf("sfDestination"), bob);
        tx.set_field_amount(sf("sfFee"), xrp(2_000_000));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let result = full_apply(&mut view, &tx, TxType::ACCOUNT_DELETE);
    if result == Ter::TES_SUCCESS {
        // Bob should have received alice's balance minus fee
        let bob_bal = view
            .read(account_keylet(acct_id(bob)))
            .unwrap()
            .unwrap()
            .get_field_amount(sf("sfBalance"))
            .xrp()
            .drops();
        assert!(
            bob_bal > 1_000_000_000,
            "Bob should have more, got {}",
            bob_bal
        );
    }
}

