#[test]
fn offer_unfunded_after_payment_drains_balance() {
    let alice = acct(0x11);
    let bob = acct(0x22);
    let gw = acct(0x33);
    let usd = usd_currency();
    let ledger = build_ledger(vec![
        account_root(alice, 5_000_000_000, 1, 0),
        account_root(bob, 5_000_000_000, 1, 0),
        account_root(gw, 5_000_000_000, 0, 0),
        trust_line(alice, gw, usd, 1000, 10000, 0),
        trust_line(bob, gw, usd, 0, 10000, 0),
    ]);
    let mut view = new_view(ledger);
    // Alice sends all her USD to bob
    let tx1 = STTx::new(TxType::PAYMENT, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_account_id(sf("sfDestination"), bob);
        tx.set_field_amount(sf("sfAmount"), iou(gw, usd, 1000));
        tx.set_field_amount(sf("sfSendMax"), iou(gw, usd, 1000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let r1 = handle_real_dispatch(&mut view, &tx1, TxType::PAYMENT, None);
    assert!(
        r1 == Ter::TES_SUCCESS || r1 == Ter::TEC_PATH_PARTIAL,
        "payment got {:?}",
        r1
    );
    if r1 != Ter::TES_SUCCESS {
        return;
    }
    // Now alice tries to create offer selling USD — should be unfunded
    let tx2 = STTx::new(TxType::OFFER_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_amount(sf("sfTakerPays"), xrp(500_000_000));
        tx.set_field_amount(sf("sfTakerGets"), iou(gw, usd, 500));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 2);
    });
    let r = handle_real_dispatch(&mut view, &tx2, TxType::OFFER_CREATE, None);
    assert!(
        r == Ter::TEC_UNFUNDED_OFFER || r == Ter::TEC_PATH_PARTIAL,
        "Got {:?}",
        r
    );
}

#[test]
fn signer_list_with_three_signers() {
    let alice = acct(0x11);
    let ledger = build_ledger(vec![account_root(alice, 5_000_000_000, 0, 0)]);
    let mut view = new_view(ledger);
    let mut entries = STArray::new(sf("sfSignerEntries"));
    for i in 0x22..0x25u8 {
        let mut e = STObject::make_inner_object(sf("sfSignerEntry"));
        e.set_account_id(sf("sfAccount"), acct(i));
        e.set_field_u16(sf("sfSignerWeight"), 1);
        entries.push_back(e);
    }
    let tx = STTx::new(TxType::SIGNER_LIST_SET, move |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_u32(sf("sfSignerQuorum"), 2);
        tx.set_field_array(sf("sfSignerEntries"), entries.clone());
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        full_apply(&mut view, &tx, TxType::SIGNER_LIST_SET),
        Ter::TES_SUCCESS
    );
}

