#[test]
fn offer_crossing_three_offers_at_same_quality() {
    let alice = acct(0x11);
    let bob = acct(0x22);
    let carol = acct(0x44);
    let dave = acct(0x55);
    let gw = acct(0x33);
    let usd = usd_currency();
    let ledger = build_ledger(vec![
        account_root(alice, 10_000_000_000, 1, 0),
        account_root(bob, 10_000_000_000, 1, 0),
        account_root(carol, 10_000_000_000, 1, 0),
        account_root(dave, 10_000_000_000, 1, 0),
        account_root(gw, 10_000_000_000, 0, 0),
        trust_line(alice, gw, usd, 300, 10000, 0),
        trust_line(bob, gw, usd, 300, 10000, 0),
        trust_line(carol, gw, usd, -300, 0, 10000),
        trust_line(dave, gw, usd, 0, 10000, 0),
    ]);
    let mut view = new_view(ledger);
    // Three sellers at same price
    for (i, seller) in [alice, bob, carol].iter().enumerate() {
        let tx = STTx::new(TxType::OFFER_CREATE, |tx| {
            tx.set_account_id(sf("sfAccount"), *seller);
            tx.set_field_amount(sf("sfTakerPays"), xrp(300_000_000));
            tx.set_field_amount(sf("sfTakerGets"), iou(gw, usd, 300));
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), 1);
        });
        assert_eq!(
            handle_real_dispatch(&mut view, &tx, TxType::OFFER_CREATE, None),
            Ter::TES_SUCCESS
        );
    }
    // Dave buys all 900 USD
    let tx = STTx::new(TxType::OFFER_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), dave);
        tx.set_field_amount(sf("sfTakerPays"), iou(gw, usd, 900));
        tx.set_field_amount(sf("sfTakerGets"), xrp(900_000_000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        handle_real_dispatch(&mut view, &tx, TxType::OFFER_CREATE, None),
        Ter::TES_SUCCESS
    );
}

