#[test]
fn paychan_create_then_fund_then_close() {
    let alice = acct(0x11);
    let bob = acct(0x22);
    let ledger = build_ledger(vec![
        account_root(alice, 10_000_000_000, 0, 0),
        account_root(bob, 5_000_000_000, 0, 0),
    ]);
    let mut view = new_view(ledger);
    let tx1 = STTx::new(TxType::PAYCHAN_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_account_id(sf("sfDestination"), bob);
        tx.set_field_amount(sf("sfAmount"), xrp(500_000_000));
        tx.set_field_u32(sf("sfSettleDelay"), 60);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        full_apply(&mut view, &tx1, TxType::PAYCHAN_CREATE),
        Ter::TES_SUCCESS
    );
    let chan = protocol::pay_channel_keylet(acct_id(alice), acct_id(bob), 1);
    let tx2 = STTx::new(TxType::PAYCHAN_FUND, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_h256(sf("sfChannel"), chan.key);
        tx.set_field_amount(sf("sfAmount"), xrp(200_000_000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 2);
    });
    assert_eq!(
        full_apply(&mut view, &tx2, TxType::PAYCHAN_FUND),
        Ter::TES_SUCCESS
    );
    let tx3 = STTx::new(TxType::PAYCHAN_CLAIM, |tx| {
        tx.set_account_id(sf("sfAccount"), bob);
        tx.set_field_h256(sf("sfChannel"), chan.key);
        tx.set_field_u32(sf("sfFlags"), 0x00020000);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        full_apply(&mut view, &tx3, TxType::PAYCHAN_CLAIM),
        Ter::TES_SUCCESS
    );
}

