#[test]
fn signer_list_set_weighted_quorum() {
    let alice = acct(0x11);
    let ledger = build_ledger(vec![account_root(alice, 5_000_000_000, 0, 0)]);
    let mut view = new_view(ledger);
    let mut entries = STArray::new(sf("sfSignerEntries"));
    let mut e1 = STObject::make_inner_object(sf("sfSignerEntry"));
    e1.set_account_id(sf("sfAccount"), acct(0x22));
    e1.set_field_u16(sf("sfSignerWeight"), 3);
    entries.push_back(e1);
    let mut e2 = STObject::make_inner_object(sf("sfSignerEntry"));
    e2.set_account_id(sf("sfAccount"), acct(0x33));
    e2.set_field_u16(sf("sfSignerWeight"), 2);
    entries.push_back(e2);
    let mut e3 = STObject::make_inner_object(sf("sfSignerEntry"));
    e3.set_account_id(sf("sfAccount"), acct(0x44));
    e3.set_field_u16(sf("sfSignerWeight"), 1);
    entries.push_back(e3);
    let tx = STTx::new(TxType::SIGNER_LIST_SET, move |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_u32(sf("sfSignerQuorum"), 5); // need weight >= 5
        tx.set_field_array(sf("sfSignerEntries"), entries.clone());
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        full_apply(&mut view, &tx, TxType::SIGNER_LIST_SET),
        Ter::TES_SUCCESS
    );
}

