#[test]
fn trust_set_then_payment_then_delete_line() {
    let alice = acct(0x11);
    let gw = acct(0x33);
    let usd = usd_currency();
    let lsf_dr: u32 = 0x00800000;
    let ledger = build_ledger(vec![
        account_root(alice, 5_000_000_000, 0, lsf_dr),
        account_root(gw, 5_000_000_000, 0, lsf_dr),
    ]);
    let mut view = new_view(ledger);
    // Create trust line
    let tx1 = STTx::new(TxType::TRUST_SET, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_amount(
            sf("sfLimitAmount"),
            STAmount::from_iou_amount(
                sf_generic(),
                IOUAmount::from_parts(1000, 0).expect("a"),
                Issue::new(usd, gw),
            ),
        );
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        full_apply(&mut view, &tx1, TxType::TRUST_SET),
        Ter::TES_SUCCESS
    );
    // gw sends IOU
    let tx2 = STTx::new(TxType::PAYMENT, |tx| {
        tx.set_account_id(sf("sfAccount"), gw);
        tx.set_account_id(sf("sfDestination"), alice);
        tx.set_field_amount(sf("sfAmount"), iou(gw, usd, 500));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        handle_real_dispatch(&mut view, &tx2, TxType::PAYMENT, None),
        Ter::TES_SUCCESS
    );
    // alice sends all back
    let tx3 = STTx::new(TxType::PAYMENT, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_account_id(sf("sfDestination"), gw);
        tx.set_field_amount(sf("sfAmount"), iou(gw, usd, 500));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 2);
    });
    assert_eq!(
        handle_real_dispatch(&mut view, &tx3, TxType::PAYMENT, None),
        Ter::TES_SUCCESS
    );
    // Delete trust line (zero limit, zero balance)
    let tx4 = STTx::new(TxType::TRUST_SET, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_amount(
            sf("sfLimitAmount"),
            STAmount::from_iou_amount(
                sf_generic(),
                IOUAmount::from_parts(0, 0).expect("a"),
                Issue::new(usd, gw),
            ),
        );
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 3);
    });
    assert_eq!(
        full_apply(&mut view, &tx4, TxType::TRUST_SET),
        Ter::TES_SUCCESS
    );
    assert_eq!(get_owner_count(&view, alice), 0);
}

