#[test]
fn offer_create_then_payment_uses_offer() {
    let alice = acct(0x11);
    let bob = acct(0x22);
    let gw = acct(0x33);
    let usd = usd_currency();
    let l = build_ledger(vec![
        account_root(alice, 10_000_000_000, 1, 0),
        account_root(bob, 10_000_000_000, 1, 0),
        account_root(gw, 10_000_000_000, 0, 0),
        trust_line(alice, gw, usd, 1000, 10000, 0),
        trust_line(bob, gw, usd, 0, 10000, 0),
    ]);
    let mut v = new_view(l);
    // Alice places offer: sell USD for XRP
    let tx1 = STTx::new(TxType::OFFER_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), alice);
        tx.set_field_amount(sf("sfTakerPays"), xrp(1_000_000_000));
        tx.set_field_amount(sf("sfTakerGets"), iou(gw, usd, 1000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        handle_real_dispatch(&mut v, &tx1, TxType::OFFER_CREATE, None),
        Ter::TES_SUCCESS
    );
    // Bob pays carol USD using XRP through alice's offer (cross-currency payment)
    // This tests the payment engine using the DEX
    let tx2 = STTx::new(TxType::PAYMENT, |tx| {
        tx.set_account_id(sf("sfAccount"), bob);
        tx.set_account_id(sf("sfDestination"), bob);
        tx.set_field_amount(sf("sfAmount"), iou(gw, usd, 100));
        tx.set_field_amount(sf("sfSendMax"), xrp(200_000_000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let r = handle_real_dispatch(&mut v, &tx2, TxType::PAYMENT, None);
    // Cross-currency payment may or may not work depending on path finding
    assert!(
        r == Ter::TES_SUCCESS
            || r == Ter::TEC_PATH_DRY
            || r == Ter::TEC_PATH_PARTIAL
            || r == Ter::TEM_REDUNDANT,
        "Got {:?}",
        r
    );
}

#[test]
fn deposit_preauth_five_accounts() {
    let alice = acct(0x11);
    let l = build_ledger(vec![
        account_root(alice, 10_000_000_000, 0, 0),
        account_root(acct(0x22), 1_000_000_000, 0, 0),
        account_root(acct(0x33), 1_000_000_000, 0, 0),
        account_root(acct(0x44), 1_000_000_000, 0, 0),
        account_root(acct(0x55), 1_000_000_000, 0, 0),
        account_root(acct(0x66), 1_000_000_000, 0, 0),
    ]);
    let mut v = new_view(l);
    for (i, fill) in [0x22u8, 0x33, 0x44, 0x55, 0x66].iter().enumerate() {
        let tx = STTx::new(TxType::DEPOSIT_PREAUTH, |tx| {
            tx.set_account_id(sf("sfAccount"), alice);
            tx.set_account_id(sf("sfAuthorize"), acct(*fill));
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), (i + 1) as u32);
        });
        assert_eq!(
            full_apply(&mut v, &tx, TxType::DEPOSIT_PREAUTH),
            Ter::TES_SUCCESS
        );
    }
    assert_eq!(get_owner_count(&v, alice), 5);
}

