#[test]
fn b14_deposit_preauth_three_then_remove_one() {
    let a = acct(0x11);
    let b = acct(0x22);
    let c = acct(0x44);
    let d = acct(0x55);
    let l = build_ledger(vec![
        account_root(a, 5_000_000_000, 0, 0),
        account_root(b, 1_000_000_000, 0, 0),
        account_root(c, 1_000_000_000, 0, 0),
        account_root(d, 1_000_000_000, 0, 0),
    ]);
    let mut v = new_view(l);
    for (i, t) in [b, c, d].iter().enumerate() {
        let tx = STTx::new(TxType::DEPOSIT_PREAUTH, |tx| {
            tx.set_account_id(sf("sfAccount"), a);
            tx.set_account_id(sf("sfAuthorize"), *t);
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), (i + 1) as u32);
        });
        assert_eq!(
            full_apply(&mut v, &tx, TxType::DEPOSIT_PREAUTH),
            Ter::TES_SUCCESS
        );
    }
    assert_eq!(get_owner_count(&v, a), 3);
    let tx = STTx::new(TxType::DEPOSIT_PREAUTH, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_account_id(sf("sfUnauthorize"), c);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 4);
    });
    assert_eq!(
        full_apply(&mut v, &tx, TxType::DEPOSIT_PREAUTH),
        Ter::TES_SUCCESS
    );
    assert_eq!(get_owner_count(&v, a), 2);
}

