#[test]
fn b15_offer_crossing_then_ioc_on_remainder() {
    let a = acct(0x11);
    let b = acct(0x22);
    let c = acct(0x44);
    let gw = acct(0x33);
    let usd = usd_currency();
    let l = build_ledger(vec![
        account_root(a, 10_000_000_000, 1, 0),
        account_root(b, 10_000_000_000, 1, 0),
        account_root(c, 10_000_000_000, 1, 0),
        account_root(gw, 10_000_000_000, 0, 0),
        trust_line(a, gw, usd, 1000, 10000, 0),
        trust_line(b, gw, usd, 0, 10000, 0),
        trust_line(c, gw, usd, 0, 10000, 0),
    ]);
    let mut v = new_view(l);
    let tx1 = STTx::new(TxType::OFFER_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_amount(sf("sfTakerPays"), xrp(1_000_000_000));
        tx.set_field_amount(sf("sfTakerGets"), iou(gw, usd, 1000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        handle_real_dispatch(&mut v, &tx1, TxType::OFFER_CREATE, None),
        Ter::TES_SUCCESS
    );
    let tx2 = STTx::new(TxType::OFFER_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), b);
        tx.set_field_amount(sf("sfTakerPays"), iou(gw, usd, 500));
        tx.set_field_amount(sf("sfTakerGets"), xrp(500_000_000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        handle_real_dispatch(&mut v, &tx2, TxType::OFFER_CREATE, None),
        Ter::TES_SUCCESS
    );
    let tx3 = STTx::new(TxType::OFFER_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), c);
        tx.set_field_amount(sf("sfTakerPays"), iou(gw, usd, 500));
        tx.set_field_amount(sf("sfTakerGets"), xrp(500_000_000));
        tx.set_field_u32(sf("sfFlags"), 0x00020000);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        handle_real_dispatch(&mut v, &tx3, TxType::OFFER_CREATE, None),
        Ter::TES_SUCCESS
    );
}

