#[test]
fn b15_signer_list_quorum_one() {
    let a = acct(0x11);
    let l = build_ledger(vec![account_root(a, 5_000_000_000, 0, 0)]);
    let mut v = new_view(l);
    let mut entries = STArray::new(sf("sfSignerEntries"));
    let mut e = STObject::make_inner_object(sf("sfSignerEntry"));
    e.set_account_id(sf("sfAccount"), acct(0x22));
    e.set_field_u16(sf("sfSignerWeight"), 1);
    entries.push_back(e);
    let tx = STTx::new(TxType::SIGNER_LIST_SET, move |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_u32(sf("sfSignerQuorum"), 1);
        tx.set_field_array(sf("sfSignerEntries"), entries.clone());
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        full_apply(&mut v, &tx, TxType::SIGNER_LIST_SET),
        Ter::TES_SUCCESS
    );
}

