#[test]
fn b16_offer_create_eight_offers_cancel_four() {
    let a = acct(0x11);
    let gw = acct(0x33);
    let usd = usd_currency();
    let l = build_ledger(vec![
        account_root(a, 50_000_000_000, 1, 0),
        account_root(gw, 10_000_000_000, 0, 0),
        trust_line(a, gw, usd, 50000, 100000, 0),
    ]);
    let mut v = new_view(l);
    for i in 1..=8u32 {
        let tx = STTx::new(TxType::OFFER_CREATE, |tx| {
            tx.set_account_id(sf("sfAccount"), a);
            tx.set_field_amount(sf("sfTakerPays"), xrp(100_000_000));
            tx.set_field_amount(sf("sfTakerGets"), iou(gw, usd, 100));
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), i);
        });
        assert_eq!(
            handle_real_dispatch(&mut v, &tx, TxType::OFFER_CREATE, None),
            Ter::TES_SUCCESS
        );
    }
    assert_eq!(get_owner_count(&v, a), 9);
    for i in 1..=4u32 {
        let tx = STTx::new(TxType::OFFER_CANCEL, |tx| {
            tx.set_account_id(sf("sfAccount"), a);
            tx.set_field_u32(sf("sfOfferSequence"), i);
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), i + 8);
        });
        assert_eq!(
            full_apply(&mut v, &tx, TxType::OFFER_CANCEL),
            Ter::TES_SUCCESS
        );
    }
    assert_eq!(get_owner_count(&v, a), 5);
}

