#[test]
fn b16_deposit_preauth_ten_accounts() {
    let a = acct(0x11);
    let mut entries = vec![account_root(a, 10_000_000_000, 0, 0)];
    for i in 0x20..0x2Au8 {
        entries.push(account_root(acct(i), 1_000_000_000, 0, 0));
    }
    let l = build_ledger(entries);
    let mut v = new_view(l);
    for (i, fill) in (0x20..0x2Au8).enumerate() {
        let tx = STTx::new(TxType::DEPOSIT_PREAUTH, |tx| {
            tx.set_account_id(sf("sfAccount"), a);
            tx.set_account_id(sf("sfAuthorize"), acct(fill));
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), (i + 1) as u32);
        });
        assert_eq!(
            full_apply(&mut v, &tx, TxType::DEPOSIT_PREAUTH),
            Ter::TES_SUCCESS
        );
    }
    assert_eq!(get_owner_count(&v, a), 10);
}

