#[test]
fn vault_create_then_set() {
    let a = acct(0x11);
    let gw = acct(0x33);
    let usd = usd_currency();
    let l = build_ledger_with_features(
        vec![
            account_root(a, 10_000_000_000, 0, 0),
            account_root(gw, 10_000_000_000, 0, 0),
        ],
        vec!["SingleAssetVault", "MPTokensV1", "PermissionedDomains"],
    );
    let mut v = new_view(l);
    // Create vault
    let tx1 = STTx::new(TxType::VAULT_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_amount(sf("sfAsset"), iou(gw, usd, 0));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let r1 = handle_real_dispatch(&mut v, &tx1, TxType::VAULT_CREATE, None);
    if r1 != Ter::TES_SUCCESS {
        return;
    } // skip if create fails

    // Get vault keylet
    let vault_key = protocol::vault_keylet(acct_id(a), 1).key;

    // Set on the vault
    let tx2 = STTx::new(TxType::VAULT_SET, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_h256(sf("sfVaultID"), vault_key);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 2);
    });
    let r2 = handle_real_dispatch(&mut v, &tx2, TxType::VAULT_SET, None);
    assert!(
        r2 == Ter::TES_SUCCESS || r2 == Ter::TEC_NO_ENTRY,
        "Set got {:?}",
        r2
    );
}

