// ─── Batch with inner transactions ─────────────────────────────────────────

#[test]
fn batch_with_raw_transactions() {
    let a = acct(0x11);
    let b = acct(0x22);
    let l = build_ledger_with_features(
        vec![
            account_root(a, 10_000_000_000, 0, 0),
            account_root(b, 5_000_000_000, 0, 0),
        ],
        vec!["Batch"],
    );
    let mut v = new_view(l);

    // Create a batch with inner payment
    let mut raw_txns = STArray::new(sf("sfRawTransactions"));
    let mut inner = STObject::make_inner_object(sf("sfRawTransaction"));
    inner.set_field_u16(sf("sfTransactionType"), 0); // Payment
    inner.set_account_id(sf("sfAccount"), a);
    inner.set_account_id(sf("sfDestination"), b);
    inner.set_field_amount(sf("sfAmount"), xrp(100_000));
    inner.set_field_u32(sf("sfSequence"), 0);
    raw_txns.push_back(inner);

    let tx = STTx::new(TxType::BATCH, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_u32(sf("sfFlags"), 0x01); // tfAllOrNothing
        tx.set_field_array(sf("sfRawTransactions"), raw_txns.clone());
        tx.set_field_amount(sf("sfFee"), xrp(20));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let r = handle_real_dispatch(&mut v, &tx, TxType::BATCH, None);
    // Batch may succeed or fail depending on inner tx validation
    assert!(r != Ter::TEM_DISABLED, "Batch got {:?}", r);
}

