// ─── Full Vault Deposit/Withdraw with DefaultRipple issuer ─────────────────

#[test]
fn vault_full_deposit_withdraw_lifecycle() {
    let owner = acct(0x11);
    let gw = acct(0x33);
    let usd = usd_currency();
    let l = build_ledger_with_features(
        vec![
            account_root(owner, 10_000_000_000, 1, 0),
            account_root(gw, 10_000_000_000, 0, 0x00800000), // lsfDefaultRipple
            trust_line(owner, gw, usd, 5000, 100000, 0),
        ],
        vec!["SingleAssetVault", "MPTokensV1", "PermissionedDomains"],
    );
    let mut v = new_view(l);

    // Create vault
    let tx1 = STTx::new(TxType::VAULT_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), owner);
        tx.set_field_amount(sf("sfAsset"), iou(gw, usd, 0));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let r1 = handle_real_dispatch(&mut v, &tx1, TxType::VAULT_CREATE, None);
    assert_eq!(r1, Ter::TES_SUCCESS, "Vault create failed: {:?}", r1);

    // Deposit into vault
    let vault_key = protocol::vault_keylet(acct_id(owner), 1).key;
    let tx2 = STTx::new(TxType::VAULT_DEPOSIT, |tx| {
        tx.set_account_id(sf("sfAccount"), owner);
        tx.set_field_h256(sf("sfVaultID"), vault_key);
        tx.set_field_amount(sf("sfAmount"), iou(gw, usd, 1000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 2);
    });
    let r2 = handle_real_dispatch(&mut v, &tx2, TxType::VAULT_DEPOSIT, None);
    assert_eq!(r2, Ter::TES_SUCCESS, "Vault deposit failed: {:?}", r2);

    // Withdraw from vault
    let tx3 = STTx::new(TxType::VAULT_WITHDRAW, |tx| {
        tx.set_account_id(sf("sfAccount"), owner);
        tx.set_field_h256(sf("sfVaultID"), vault_key);
        tx.set_field_amount(sf("sfAmount"), iou(gw, usd, 500));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 3);
    });
    let r3 = handle_real_dispatch(&mut v, &tx3, TxType::VAULT_WITHDRAW, None);
    assert!(
        r3 == Ter::TES_SUCCESS || r3 == Ter::TEC_PATH_PARTIAL || r3 == Ter::TEC_INSUFFICIENT_FUNDS,
        "Vault withdraw got {:?}",
        r3
    );
}

