#[test]
fn vault_deposit_from_frozen_trust_line() {
    let o = acct(0x11);
    let gw = acct(0x33);
    let usd = usd_currency();
    let mut tl = trust_line(o, gw, usd, 5000, 100000, 0);
    tl.set_field_u32(sf("sfFlags"), 0x00400000);
    let l = build_ledger_with_features(
        vec![
            account_root(o, 10_000_000_000, 1, 0),
            account_root(gw, 10_000_000_000, 0, 0x00800000),
            tl,
        ],
        vec!["SingleAssetVault", "MPTokensV1", "PermissionedDomains"],
    );
    let mut v = new_view(l);
    let tx1 = STTx::new(TxType::VAULT_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), o);
        tx.set_field_amount(sf("sfAsset"), iou(gw, usd, 0));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        handle_real_dispatch(&mut v, &tx1, TxType::VAULT_CREATE, None),
        Ter::TES_SUCCESS
    );
    let vk = protocol::vault_keylet(acct_id(o), 1).key;
    let tx2 = STTx::new(TxType::VAULT_DEPOSIT, |tx| {
        tx.set_account_id(sf("sfAccount"), o);
        tx.set_field_h256(sf("sfVaultID"), vk);
        tx.set_field_amount(sf("sfAmount"), iou(gw, usd, 100));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 2);
    });
    let r = handle_real_dispatch(&mut v, &tx2, TxType::VAULT_DEPOSIT, None);
    assert!(
        r == Ter::TEC_FROZEN
            || r == Ter::TEC_PATH_DRY
            || r == Ter::TEC_PATH_PARTIAL
            || r == Ter::TES_SUCCESS,
        "Frozen deposit got {:?}",
        r
    );
}

