// --- AMM pool operations after creation ---

#[test]
fn amm_create_then_deposit() {
    let a = acct(0x11);
    let gw = acct(0x33);
    let usd = usd_currency();
    let l = build_ledger_with_features(
        vec![
            account_root(a, 50_000_000_000, 1, 0),
            account_root(gw, 50_000_000_000, 0, 0x00800000),
            trust_line(a, gw, usd, 100000, 1000000, 0),
        ],
        vec!["AMM"],
    );
    let mut v = new_view(l);
    let tx1 = STTx::new(TxType::AMM_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_amount(sf("sfAmount"), xrp(10_000_000_000));
        tx.set_field_amount(sf("sfAmount2"), iou(gw, usd, 10000));
        tx.set_field_u16(sf("sfTradingFee"), 100);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let r1 = full_apply(&mut v, &tx1, TxType::AMM_CREATE);
    assert_eq!(r1, Ter::TES_SUCCESS);
    let tx2 = STTx::new(TxType::AMM_DEPOSIT, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_issue(
            sf("sfAsset"),
            STIssue::new_with_asset(sf("sfAsset"), Asset::Issue(Issue::new(usd, gw))),
        );
        tx.set_field_issue(
            sf("sfAsset2"),
            STIssue::new_with_asset(sf("sfAsset2"), Asset::Issue(protocol::xrp_issue())),
        );
        tx.set_field_amount(sf("sfAmount"), iou(gw, usd, 1000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfFlags"), 0x0008_0000);
        tx.set_field_u32(sf("sfSequence"), 2);
    });
    let r2 = full_apply(&mut v, &tx2, TxType::AMM_DEPOSIT);
    assert!(
        r2 == Ter::TES_SUCCESS || r2 == Ter::TER_NO_AMM,
        "Deposit {:?}",
        r2
    );
}

