#[test]
fn batch_five_inner_txns() {
    let a = acct(0x11);
    let l = build_ledger_with_features(
        vec![
            account_root(a, 50_000_000_000, 0, 0),
            account_root(acct(0x22), 1_000_000_000, 0, 0),
            account_root(acct(0x33), 1_000_000_000, 0, 0),
            account_root(acct(0x44), 1_000_000_000, 0, 0),
            account_root(acct(0x55), 1_000_000_000, 0, 0),
            account_root(acct(0x66), 1_000_000_000, 0, 0),
        ],
        vec!["Batch"],
    );
    let mut v = new_view(l);
    let mut raw = STArray::new(sf("sfRawTransactions"));
    for (i, fill) in [0x22u8, 0x33, 0x44, 0x55, 0x66].iter().enumerate() {
        let mut inner = STObject::make_inner_object(sf("sfRawTransaction"));
        inner.set_field_u16(sf("sfTransactionType"), 0);
        inner.set_account_id(sf("sfAccount"), a);
        inner.set_account_id(sf("sfDestination"), acct(*fill));
        inner.set_field_amount(sf("sfAmount"), xrp(50_000));
        inner.set_field_u32(sf("sfSequence"), i as u32);
        raw.push_back(inner);
    }
    let tx = STTx::new(TxType::BATCH, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_u32(sf("sfFlags"), 0x01);
        tx.set_field_array(sf("sfRawTransactions"), raw.clone());
        tx.set_field_amount(sf("sfFee"), xrp(50));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let r = handle_real_dispatch(&mut v, &tx, TxType::BATCH, None);
    assert!(r != Ter::TEM_DISABLED, "Batch 5 {:?}", r);
}

