#[test]
fn batch_with_offer_create_inner() {
    let a = acct(0x11);
    let gw = acct(0x33);
    let l = build_ledger_with_features(
        vec![
            account_root(a, 10_000_000_000, 0, 0),
            account_root(gw, 10_000_000_000, 0, 0),
        ],
        vec!["Batch"],
    );
    let mut v = new_view(l);
    let mut raw = STArray::new(sf("sfRawTransactions"));
    let mut inner = STObject::make_inner_object(sf("sfRawTransaction"));
    inner.set_field_u16(sf("sfTransactionType"), 7);
    inner.set_account_id(sf("sfAccount"), a);
    inner.set_field_u32(sf("sfSequence"), 0);
    raw.push_back(inner);
    let tx = STTx::new(TxType::BATCH, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_u32(sf("sfFlags"), 0x01);
        tx.set_field_array(sf("sfRawTransactions"), raw.clone());
        tx.set_field_amount(sf("sfFee"), xrp(20));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let r = handle_real_dispatch(&mut v, &tx, TxType::BATCH, None);
    assert!(r != Ter::TEM_DISABLED, "Batch offer {:?}", r);
}

#[test]
fn vault_deposit_then_set_then_deposit() {
    let o = acct(0x11);
    let gw = acct(0x33);
    let usd = usd_currency();
    let l = build_ledger_with_features(
        vec![
            account_root(o, 10_000_000_000, 1, 0),
            account_root(gw, 10_000_000_000, 0, 0x00800000),
            trust_line(o, gw, usd, 50000, 100000, 0),
        ],
        vec!["SingleAssetVault", "MPTokensV1", "PermissionedDomains"],
    );
    let mut v = new_view(l);
    let tx1 = STTx::new(TxType::VAULT_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), o);
        tx.set_field_amount(sf("sfAsset"), iou(gw, usd, 0));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        handle_real_dispatch(&mut v, &tx1, TxType::VAULT_CREATE, None),
        Ter::TES_SUCCESS
    );
    let vk = protocol::vault_keylet(acct_id(o), 1).key;
    let tx2 = STTx::new(TxType::VAULT_DEPOSIT, |tx| {
        tx.set_account_id(sf("sfAccount"), o);
        tx.set_field_h256(sf("sfVaultID"), vk);
        tx.set_field_amount(sf("sfAmount"), iou(gw, usd, 500));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 2);
    });
    assert_eq!(
        handle_real_dispatch(&mut v, &tx2, TxType::VAULT_DEPOSIT, None),
        Ter::TES_SUCCESS
    );
    let tx3 = STTx::new(TxType::VAULT_SET, |tx| {
        tx.set_account_id(sf("sfAccount"), o);
        tx.set_field_h256(sf("sfVaultID"), vk);
        tx.set_field_vl(sf("sfData"), b"updated");
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 3);
    });
    assert_eq!(
        handle_real_dispatch(&mut v, &tx3, TxType::VAULT_SET, None),
        Ter::TES_SUCCESS
    );
    let tx4 = STTx::new(TxType::VAULT_DEPOSIT, |tx| {
        tx.set_account_id(sf("sfAccount"), o);
        tx.set_field_h256(sf("sfVaultID"), vk);
        tx.set_field_amount(sf("sfAmount"), iou(gw, usd, 500));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 4);
    });
    assert_eq!(
        handle_real_dispatch(&mut v, &tx4, TxType::VAULT_DEPOSIT, None),
        Ter::TES_SUCCESS
    );
}

#[test]
fn credential_create_accept_delete_cycle() {
    let i = acct(0x11);
    let s = acct(0x22);
    let l = build_ledger(vec![
        account_root(i, 10_000_000_000, 0, 0),
        account_root(s, 10_000_000_000, 0, 0),
    ]);
    let mut v = new_view(l);
    for n in 1..=3u32 {
        let ct = format!("CYC{}", n);
        let tx1 = STTx::new(TxType::CREDENTIAL_CREATE, |tx| {
            tx.set_account_id(sf("sfAccount"), i);
            tx.set_account_id(sf("sfSubject"), s);
            tx.set_field_vl(sf("sfCredentialType"), ct.as_bytes());
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), n * 3 - 2);
        });
        assert_eq!(
            handle_real_dispatch(&mut v, &tx1, TxType::CREDENTIAL_CREATE, None),
            Ter::TES_SUCCESS
        );
        let tx2 = STTx::new(TxType::CREDENTIAL_ACCEPT, |tx| {
            tx.set_account_id(sf("sfAccount"), s);
            tx.set_account_id(sf("sfIssuer"), i);
            tx.set_field_vl(sf("sfCredentialType"), ct.as_bytes());
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), n * 3 - 1);
        });
        assert_eq!(
            handle_real_dispatch(&mut v, &tx2, TxType::CREDENTIAL_ACCEPT, None),
            Ter::TES_SUCCESS
        );
        let tx3 = STTx::new(TxType::CREDENTIAL_DELETE, |tx| {
            tx.set_account_id(sf("sfAccount"), i);
            tx.set_account_id(sf("sfSubject"), s);
            tx.set_account_id(sf("sfIssuer"), i);
            tx.set_field_vl(sf("sfCredentialType"), ct.as_bytes());
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), n * 3);
        });
        assert_eq!(
            handle_real_dispatch(&mut v, &tx3, TxType::CREDENTIAL_DELETE, None),
            Ter::TES_SUCCESS
        );
    }
}

