#[test]
fn ledger_view_erase() {
    let a = acct(0x11);
    let l = build_ledger(vec![account_root(a, 5_000_000_000, 0, 0)]);
    let mut v = new_view(l);
    let keylet = protocol::check_keylet(acct_id(a), 99);
    let mut sle = STLedgerEntry::new(keylet.clone());
    sle.set_account_id(sf("sfAccount"), a);
    let sle_arc = std::sync::Arc::new(sle);
    let _ = v.insert(sle_arc.clone());
    assert!(v.exists(keylet.clone()).unwrap());
    let _ = v.erase(sle_arc);
    assert!(!v.exists(keylet).unwrap_or(true));
}

