#[test]
fn ledger_xrp_liquid_above_reserve() {
    let a = acct(0x11);
    let l = build_ledger(vec![account_root(a, 1_000_000, 0, 0)]);
    let v = new_view(l);
    let sle = v.read(account_keylet(acct_id(a))).unwrap().unwrap();
    let bal = sle.get_field_amount(sf("sfBalance")).xrp().drops();
    let oc = sle.get_field_u32(sf("sfOwnerCount"));
    let reserve = 200_000 + 50_000 * oc as i64;
    let liquid = (bal - reserve).max(0);
    assert_eq!(liquid, 800_000);
}

