#[test]
fn ledger_multiple_trust_lines_same_account() {
    let a = acct(0x11);
    let gw = acct(0x33);
    let l = build_ledger(vec![
        account_root(a, 5_000_000_000, 0, 0),
        account_root(gw, 5_000_000_000, 0, 0),
    ]);
    let mut v = new_view(l);
    for (i, cur) in ["USD", "EUR", "GBP", "JPY", "CHF"].iter().enumerate() {
        let c = protocol::currency_from_string(cur);
        let tx = STTx::new(TxType::TRUST_SET, |tx| {
            tx.set_account_id(sf("sfAccount"), a);
            tx.set_field_amount(
                sf("sfLimitAmount"),
                STAmount::from_iou_amount(
                    sf_generic(),
                    IOUAmount::from_parts(1000, 0).expect("a"),
                    Issue::new(c, gw),
                ),
            );
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), (i + 1) as u32);
        });
        assert_eq!(full_apply(&mut v, &tx, TxType::TRUST_SET), Ter::TES_SUCCESS);
    }
    assert_eq!(get_owner_count(&v, a), 5);
}

