#[test]
fn ls5_deposit_preauth_five_then_remove_all() {
    let a = acct(0x11);
    let mut entries = vec![account_root(a, 10_000_000_000, 0, 0)];
    for i in 0x22..0x27u8 {
        entries.push(account_root(acct(i), 1_000_000_000, 0, 0));
    }
    let l = build_ledger(entries);
    let mut v = new_view(l);
    for (i, fill) in (0x22..0x27u8).enumerate() {
        let tx = STTx::new(TxType::DEPOSIT_PREAUTH, |tx| {
            tx.set_account_id(sf("sfAccount"), a);
            tx.set_account_id(sf("sfAuthorize"), acct(fill));
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), (i + 1) as u32);
        });
        assert_eq!(
            full_apply(&mut v, &tx, TxType::DEPOSIT_PREAUTH),
            Ter::TES_SUCCESS
        );
    }
    assert_eq!(get_owner_count(&v, a), 5);
    for (i, fill) in (0x22..0x27u8).enumerate() {
        let tx = STTx::new(TxType::DEPOSIT_PREAUTH, |tx| {
            tx.set_account_id(sf("sfAccount"), a);
            tx.set_account_id(sf("sfUnauthorize"), acct(fill));
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), (i + 6) as u32);
        });
        assert_eq!(
            full_apply(&mut v, &tx, TxType::DEPOSIT_PREAUTH),
            Ter::TES_SUCCESS
        );
    }
    assert_eq!(get_owner_count(&v, a), 0);
}

#[test]
fn ls5_nftoken_mint_five_burn_three() {
    let a = acct(0x11);
    let l = build_ledger(vec![account_root(a, 10_000_000_000, 0, 0)]);
    let mut v = new_view(l);
    let mut token_ids = Vec::new();
    for i in 1..=5u32 {
        let tx = STTx::new(TxType::NFTOKEN_MINT, |tx| {
            tx.set_account_id(sf("sfAccount"), a);
            tx.set_field_u32(sf("sfNFTokenTaxon"), i);
            tx.set_field_u32(sf("sfFlags"), 0x01);
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), i);
        });
        assert_eq!(
            full_apply(&mut v, &tx, TxType::NFTOKEN_MINT),
            Ter::TES_SUCCESS
        );
        token_ids.push(Uint256::from(tx.get_transaction_id()));
    }
    for (i, tid) in token_ids[0..3].iter().enumerate() {
        let tx = STTx::new(TxType::NFTOKEN_BURN, |tx| {
            tx.set_account_id(sf("sfAccount"), a);
            tx.set_field_h256(sf("sfNFTokenID"), *tid);
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), (i + 6) as u32);
        });
        assert_eq!(
            full_apply(&mut v, &tx, TxType::NFTOKEN_BURN),
            Ter::TES_SUCCESS
        );
    }
}

#[test]
fn ls5_credential_lifecycle_ten() {
    let i = acct(0x11);
    let s = acct(0x22);
    let l = build_ledger(vec![
        account_root(i, 50_000_000_000, 0, 0),
        account_root(s, 50_000_000_000, 0, 0),
    ]);
    let mut v = new_view(l);
    for n in 1..=10u32 {
        let ct = format!("C{:03}", n);
        let tx1 = STTx::new(TxType::CREDENTIAL_CREATE, |tx| {
            tx.set_account_id(sf("sfAccount"), i);
            tx.set_account_id(sf("sfSubject"), s);
            tx.set_field_vl(sf("sfCredentialType"), ct.as_bytes());
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), n * 2 - 1);
        });
        assert_eq!(
            handle_real_dispatch(&mut v, &tx1, TxType::CREDENTIAL_CREATE, None),
            Ter::TES_SUCCESS
        );
        let tx2 = STTx::new(TxType::CREDENTIAL_ACCEPT, |tx| {
            tx.set_account_id(sf("sfAccount"), s);
            tx.set_account_id(sf("sfIssuer"), i);
            tx.set_field_vl(sf("sfCredentialType"), ct.as_bytes());
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), n);
        });
        assert_eq!(
            handle_real_dispatch(&mut v, &tx2, TxType::CREDENTIAL_ACCEPT, None),
            Ter::TES_SUCCESS
        );
    }
}

