#[test]
fn ls5_signer_list_create_replace_delete() {
    let a = acct(0x11);
    let l = build_ledger(vec![account_root(a, 5_000_000_000, 0, 0)]);
    let mut v = new_view(l);
    let mut e1 = STArray::new(sf("sfSignerEntries"));
    let mut s1 = STObject::make_inner_object(sf("sfSignerEntry"));
    s1.set_account_id(sf("sfAccount"), acct(0x22));
    s1.set_field_u16(sf("sfSignerWeight"), 1);
    e1.push_back(s1);
    let tx1 = STTx::new(TxType::SIGNER_LIST_SET, move |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_u32(sf("sfSignerQuorum"), 1);
        tx.set_field_array(sf("sfSignerEntries"), e1.clone());
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        full_apply(&mut v, &tx1, TxType::SIGNER_LIST_SET),
        Ter::TES_SUCCESS
    );
    assert_eq!(get_owner_count(&v, a), 1);
    let mut e2 = STArray::new(sf("sfSignerEntries"));
    let mut s2 = STObject::make_inner_object(sf("sfSignerEntry"));
    s2.set_account_id(sf("sfAccount"), acct(0x33));
    s2.set_field_u16(sf("sfSignerWeight"), 2);
    e2.push_back(s2);
    let tx2 = STTx::new(TxType::SIGNER_LIST_SET, move |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_u32(sf("sfSignerQuorum"), 2);
        tx.set_field_array(sf("sfSignerEntries"), e2.clone());
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 2);
    });
    assert_eq!(
        full_apply(&mut v, &tx2, TxType::SIGNER_LIST_SET),
        Ter::TES_SUCCESS
    );
    let tx3 = STTx::new(TxType::SIGNER_LIST_SET, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_u32(sf("sfSignerQuorum"), 0);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 3);
    });
    assert_eq!(
        full_apply(&mut v, &tx3, TxType::SIGNER_LIST_SET),
        Ter::TES_SUCCESS
    );
    assert_eq!(get_owner_count(&v, a), 0);
}

