#[test]
fn ls6_check_ten_create_cash_all() {
    let a = acct(0x11);
    let b = acct(0x22);
    let l = build_ledger(vec![
        account_root(a, 50_000_000_000, 0, 0),
        account_root(b, 1_000_000_000, 0, 0),
    ]);
    let mut v = new_view(l);
    for i in 1..=10u32 {
        let tx = STTx::new(TxType::CHECK_CREATE, |tx| {
            tx.set_account_id(sf("sfAccount"), a);
            tx.set_account_id(sf("sfDestination"), b);
            tx.set_field_amount(sf("sfSendMax"), xrp(100_000));
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), i);
        });
        assert_eq!(
            full_apply(&mut v, &tx, TxType::CHECK_CREATE),
            Ter::TES_SUCCESS
        );
    }
    assert_eq!(get_owner_count(&v, a), 10);
    for i in 1..=10u32 {
        let ck = protocol::check_keylet(acct_id(a), i).key;
        let tx = STTx::new(TxType::CHECK_CASH, |tx| {
            tx.set_account_id(sf("sfAccount"), b);
            tx.set_field_h256(sf("sfCheckID"), ck);
            tx.set_field_amount(sf("sfAmount"), xrp(100_000));
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), i);
        });
        assert_eq!(
            full_apply(&mut v, &tx, TxType::CHECK_CASH),
            Ter::TES_SUCCESS
        );
    }
    assert_eq!(get_owner_count(&v, a), 0);
}

