#[test]
fn ls6_offer_crossing_five_sellers() {
    let gw = acct(0x33);
    let usd = usd_currency();
    let buyer = acct(0x66);
    let mut entries = vec![
        account_root(gw, 10_000_000_000, 0, 0),
        account_root(buyer, 50_000_000_000, 1, 0),
        trust_line(buyer, gw, usd, 0, 100000, 0),
    ];
    for i in 0x11..0x16u8 {
        entries.push(account_root(acct(i), 10_000_000_000, 1, 0));
        entries.push(trust_line(acct(i), gw, usd, 200, 10000, 0));
    }
    let l = build_ledger(entries);
    let mut v = new_view(l);
    for (i, fill) in (0x11..0x16u8).enumerate() {
        let tx = STTx::new(TxType::OFFER_CREATE, |tx| {
            tx.set_account_id(sf("sfAccount"), acct(fill));
            tx.set_field_amount(sf("sfTakerPays"), xrp(200_000_000));
            tx.set_field_amount(sf("sfTakerGets"), iou(gw, usd, 200));
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), 1);
        });
        assert_eq!(
            handle_real_dispatch(&mut v, &tx, TxType::OFFER_CREATE, None),
            Ter::TES_SUCCESS
        );
    }
    let tx = STTx::new(TxType::OFFER_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), buyer);
        tx.set_field_amount(sf("sfTakerPays"), iou(gw, usd, 1000));
        tx.set_field_amount(sf("sfTakerGets"), xrp(1_000_000_000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        handle_real_dispatch(&mut v, &tx, TxType::OFFER_CREATE, None),
        Ter::TES_SUCCESS
    );
}

#[test]
fn ls6_frozen_then_unfreeze_then_offer() {
    let a = acct(0x11);
    let gw = acct(0x33);
    let usd = usd_currency();
    let mut gw_root = account_root(gw, 10_000_000_000, 0, 0);
    gw_root.set_field_u32(sf("sfFlags"), 0x00400000);
    let l = build_ledger(vec![
        account_root(a, 10_000_000_000, 1, 0),
        gw_root,
        trust_line(a, gw, usd, 1000, 10000, 0),
    ]);
    let mut v = new_view(l);
    let tx1 = STTx::new(TxType::OFFER_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_amount(sf("sfTakerPays"), xrp(1_000_000_000));
        tx.set_field_amount(sf("sfTakerGets"), iou(gw, usd, 1000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        handle_real_dispatch(&mut v, &tx1, TxType::OFFER_CREATE, None),
        Ter::TEC_UNFUNDED_OFFER
    );
    let tx2 = STTx::new(TxType::ACCOUNT_SET, |tx| {
        tx.set_account_id(sf("sfAccount"), gw);
        tx.set_field_u32(sf("sfClearFlag"), 7);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        full_apply(&mut v, &tx2, TxType::ACCOUNT_SET),
        Ter::TES_SUCCESS
    );
    let tx3 = STTx::new(TxType::OFFER_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_amount(sf("sfTakerPays"), xrp(1_000_000_000));
        tx.set_field_amount(sf("sfTakerGets"), iou(gw, usd, 1000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 2);
    });
    assert_eq!(
        handle_real_dispatch(&mut v, &tx3, TxType::OFFER_CREATE, None),
        Ter::TES_SUCCESS
    );
}

