#[test]
fn proto_currency_from_string() {
    let usd = protocol::currency_from_string("USD");
    assert!(!usd.is_zero());
    let eur = protocol::currency_from_string("EUR");
    assert_ne!(usd, eur);
}

#[test]
fn proto_bad_currency() {
    let bad = protocol::bad_currency();
    assert!(!bad.is_zero());
}

#[test]
fn proto_xrp_issue() {
    let issue = protocol::xrp_issue();
    assert!(issue.currency.is_zero());
    assert!(issue.account.data().iter().all(|&b| b == 0));
}

