#[test]
fn proto_st_amount_xrp_positive() {
    let amt = STAmount::from_xrp_amount(XRPAmount::from_drops(1_000_000));
    assert!(amt.native());
    assert_eq!(amt.signum(), 1);
    assert_eq!(amt.xrp().drops(), 1_000_000);
}

#[test]
fn proto_st_amount_xrp_zero() {
    let amt = STAmount::from_xrp_amount(XRPAmount::from_drops(0));
    assert!(amt.native());
    assert_eq!(amt.signum(), 0);
}

#[test]
fn proto_st_amount_xrp_negative() {
    let amt = STAmount::from_xrp_amount(XRPAmount::from_drops(-500));
    assert!(amt.native());
    assert_eq!(amt.signum(), -1);
}

#[test]
fn proto_st_amount_iou() {
    let gw = acct(0x33);
    let usd = usd_currency();
    let issue = Issue::new(usd, gw);
    let amt = STAmount::from_iou_amount(
        sf_generic(),
        IOUAmount::from_parts(100, 0).expect("a"),
        issue,
    );
    assert!(!amt.native());
    assert_eq!(amt.signum(), 1);
    assert_eq!(amt.issue(), issue);
}

#[test]
