// STObject copy equality
#[test]
fn r2_obj_clone_eq() {
    let mut obj = protocol::STObject::new(sf("sfLedgerEntry"));
    obj.set_field_u32(sf("sfSequence"), 42);
    obj.set_account_id(sf("sfAccount"), acct(0x11));
    let copy = obj.clone();
    assert_eq!(copy.get_field_u32(sf("sfSequence")), 42);
    assert_eq!(copy.get_account_id(sf("sfAccount")), acct(0x11));
}
#[test]
fn r2_obj_modify_copy_independent() {
    let mut obj = protocol::STObject::new(sf("sfLedgerEntry"));
    obj.set_field_u32(sf("sfSequence"), 1);
    let mut copy = obj.clone();
    copy.set_field_u32(sf("sfSequence"), 2);
    assert_eq!(obj.get_field_u32(sf("sfSequence")), 1);
    assert_eq!(copy.get_field_u32(sf("sfSequence")), 2);
}

