// STObject field iteration and counting
#[test]
fn r3_obj_field_count_0() {
    let obj = protocol::STObject::new(sf("sfLedgerEntry"));
    assert_eq!(obj.get_count(), 0);
}
#[test]
fn r3_obj_field_count_1() {
    let mut obj = protocol::STObject::new(sf("sfLedgerEntry"));
    obj.set_field_u32(sf("sfSequence"), 1);
    assert!(obj.get_count() >= 1);
}
#[test]
fn r3_obj_field_count_3() {
    let mut obj = protocol::STObject::new(sf("sfLedgerEntry"));
    obj.set_field_u32(sf("sfSequence"), 1);
    obj.set_field_u32(sf("sfFlags"), 0);
    obj.set_account_id(sf("sfAccount"), acct(0x11));
    assert!(obj.get_count() >= 3);
}

