// Keylet consistency checks
#[test]
fn r3_keylet_account_consistent() {
    for i in 0x01u8..=0x10 {
        let k = protocol::account_keylet(acct_id(acct(i)));
        assert!(!k.key.is_zero());
    }
}
#[test]
fn r3_keylet_offer_consistent() {
    for i in 1u32..=10 {
        let k = protocol::offer_keylet(acct_id(acct(0x11)), i);
        assert!(!k.key.is_zero());
    }
}
#[test]
fn r3_keylet_escrow_consistent() {
    for i in 1u32..=10 {
        let k = protocol::escrow_keylet(acct_id(acct(0x11)), i);
        assert!(!k.key.is_zero());
    }
}
#[test]
fn r3_keylet_check_consistent() {
    for i in 1u32..=10 {
        let k = protocol::check_keylet(acct_id(acct(0x11)), i);
        assert!(!k.key.is_zero());
    }
}
#[test]
fn r3_keylet_all_different() {
    let a = acct(0x11);
    let k1 = protocol::account_keylet(acct_id(a));
    let k2 = protocol::offer_keylet(acct_id(a), 1);
    let k3 = protocol::escrow_keylet(acct_id(a), 1);
    let k4 = protocol::check_keylet(acct_id(a), 1);
    assert_ne!(k1.key, k2.key);
    assert_ne!(k2.key, k3.key);
    assert_ne!(k3.key, k4.key);
}

