// STAmount mulRound/divRound (consensus-critical rounding)
#[test]
fn sa_mul_round_up() {
    let gw = acct(0x33);
    let u = usd_currency();
    let asset = protocol::Asset::Issue(Issue::new(u, gw));
    let a = iou(gw, u, 1);
    let b = iou(gw, u, 3);
    let r = a.mul_round(&b, asset.clone(), true);
    assert!(r.signum() >= 0);
}
#[test]
fn sa_mul_round_down() {
    let gw = acct(0x33);
    let u = usd_currency();
    let asset = protocol::Asset::Issue(Issue::new(u, gw));
    let a = iou(gw, u, 1);
    let b = iou(gw, u, 3);
    let r = a.mul_round(&b, asset.clone(), false);
    assert!(r.signum() >= 0);
}
#[test]
fn sa_div_round_up() {
    let gw = acct(0x33);
    let u = usd_currency();
    let asset = protocol::Asset::Issue(Issue::new(u, gw));
    let a = iou(gw, u, 1);
    let b = iou(gw, u, 3);
    let r = a.div_round(&b, asset.clone(), true);
    assert!(r.signum() > 0);
}
#[test]
fn sa_div_round_down() {
    let gw = acct(0x33);
    let u = usd_currency();
    let asset = protocol::Asset::Issue(Issue::new(u, gw));
    let a = iou(gw, u, 1);
    let b = iou(gw, u, 3);
    let r = a.div_round(&b, asset.clone(), false);
    assert!(r.signum() > 0);
}
#[test]
fn sa_mul_round_up_ge_down() {
    let gw = acct(0x33);
    let u = usd_currency();
    let asset = protocol::Asset::Issue(Issue::new(u, gw));
    let a = iou(gw, u, 7);
    let b = iou(gw, u, 11);
    let up = a.mul_round(&b, asset.clone(), true);
    let down = a.mul_round(&b, asset, false);
    assert!(up >= down);
}
#[test]
fn sa_div_round_up_ge_down() {
    let gw = acct(0x33);
    let u = usd_currency();
    let asset = protocol::Asset::Issue(Issue::new(u, gw));
    let a = iou(gw, u, 7);
    let b = iou(gw, u, 11);
    let up = a.div_round(&b, asset.clone(), true);
    let down = a.div_round(&b, asset, false);
    assert!(up >= down);
}

