// Clone/copy behavior
#[test]
fn so_clone_preserves_u32() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u32(sf("sfSequence"), 42);
    let c = o.clone();
    assert_eq!(c.get_field_u32(sf("sfSequence")), 42);
}
#[test]
fn so_clone_preserves_account() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_account_id(sf("sfAccount"), acct(0x11));
    let c = o.clone();
    assert_eq!(c.get_account_id(sf("sfAccount")), acct(0x11));
}
#[test]
fn so_clone_preserves_amount() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_amount(sf("sfBalance"), xrp(999));
    let c = o.clone();
    assert_eq!(c.get_field_amount(sf("sfBalance")).xrp().drops(), 999);
}
#[test]
fn so_clone_independent_u32() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u32(sf("sfSequence"), 1);
    let mut c = o.clone();
    c.set_field_u32(sf("sfSequence"), 99);
    assert_eq!(o.get_field_u32(sf("sfSequence")), 1);
    assert_eq!(c.get_field_u32(sf("sfSequence")), 99);
}
#[test]
fn so_clone_independent_account() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_account_id(sf("sfAccount"), acct(0x11));
    let mut c = o.clone();
    c.set_account_id(sf("sfAccount"), acct(0x22));
    assert_eq!(o.get_account_id(sf("sfAccount")), acct(0x11));
    assert_eq!(c.get_account_id(sf("sfAccount")), acct(0x22));
}

// Serializer consistency
#[test]
fn so_serializer_same_obj() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u32(sf("sfSequence"), 42);
    let s1 = o.get_serializer();
    let s2 = o.get_serializer();
    assert_eq!(s1.size(), s2.size());
}
#[test]
fn so_serializer_diff_after_modify() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u32(sf("sfSequence"), 1);
    let s1 = o.get_serializer();
    o.set_field_u32(sf("sfSequence"), 2);
    let s2 = o.get_serializer();
    assert_ne!(s1.data(), s2.data());
}
#[test]
fn so_serializer_clone_eq() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u32(sf("sfSequence"), 42);
    o.set_account_id(sf("sfAccount"), acct(0x11));
    let c = o.clone();
    assert_eq!(o.get_serializer().data(), c.get_serializer().data());
}
#[test]
fn so_serializer_nonempty() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u32(sf("sfSequence"), 1);
    assert!(o.get_serializer().size() > 0);
}
#[test]
fn so_serializer_grows() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u32(sf("sfSequence"), 1);
    let s1 = o.get_serializer().size();
    o.set_field_u32(sf("sfFlags"), 2);
    let s2 = o.get_serializer().size();
    assert!(s2 > s1);
}

