// Mixed field operations
#[test]
fn so_mixed_all_types() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u16(sf("sfLedgerEntryType"), 0x0061);
    o.set_field_u32(sf("sfSequence"), 1);
    o.set_field_u32(sf("sfFlags"), 0);
    o.set_account_id(sf("sfAccount"), acct(0x11));
    o.set_field_amount(sf("sfBalance"), xrp(5_000_000_000));
    o.set_field_h256(sf("sfPreviousTxnID"), Uint256::from_array([0xAA; 32]));
    o.set_field_vl(sf("sfDomain"), b"test.com");
    assert_eq!(o.get_field_u16(sf("sfLedgerEntryType")), 0x0061);
    assert_eq!(o.get_field_u32(sf("sfSequence")), 1);
    assert_eq!(o.get_account_id(sf("sfAccount")), acct(0x11));
    assert_eq!(
        o.get_field_amount(sf("sfBalance")).xrp().drops(),
        5_000_000_000
    );
    assert_eq!(
        o.get_field_h256(sf("sfPreviousTxnID")),
        Uint256::from_array([0xAA; 32])
    );
    assert_eq!(o.get_field_vl(sf("sfDomain")), b"test.com");
}
#[test]
fn so_mixed_serialize_all() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u16(sf("sfLedgerEntryType"), 0x0061);
    o.set_field_u32(sf("sfSequence"), 1);
    o.set_account_id(sf("sfAccount"), acct(0x11));
    o.set_field_amount(sf("sfBalance"), xrp(1000));
    let s = o.get_serializer();
    assert!(s.size() > 20);
}
#[test]
fn so_count_after_mixed() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u32(sf("sfSequence"), 1);
    o.set_field_u32(sf("sfFlags"), 0);
    o.set_account_id(sf("sfAccount"), acct(0x11));
    o.set_field_amount(sf("sfBalance"), xrp(1000));
    assert!(o.get_count() >= 4);
}

