// Vector256 field
#[test]
fn so2_v256_empty() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_v256(
        sf("sfAmendments"),
        protocol::STVector256::from_values(sf("sfAmendments"), vec![]),
    );
    assert!(o.is_field_present(sf("sfAmendments")));
}
#[test]
fn so2_v256_one() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_v256(
        sf("sfAmendments"),
        protocol::STVector256::from_values(sf("sfAmendments"), vec![Uint256::from_array([1; 32])]),
    );
    let v = o.get_field_v256(sf("sfAmendments"));
    assert_eq!(v.value().len(), 1);
}
#[test]
fn so2_v256_five() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    let v: Vec<_> = (0..5).map(|i| Uint256::from_array([i; 32])).collect();
    o.set_field_v256(
        sf("sfAmendments"),
        protocol::STVector256::from_values(sf("sfAmendments"), v.clone()),
    );
    let got = o.get_field_v256(sf("sfAmendments"));
    assert_eq!(got.value().len(), 5);
}
#[test]
fn so2_v256_values_preserved() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    let h = Uint256::from_array([0xAB; 32]);
    o.set_field_v256(
        sf("sfAmendments"),
        protocol::STVector256::from_values(sf("sfAmendments"), vec![h]),
    );
    let got = o.get_field_v256(sf("sfAmendments"));
    assert_eq!(got.value()[0], h);
}

