// Multiple objects with same fields have same serialization
#[test]
fn so2_same_data_same_bytes() {
    let make = || {
        let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
        o.set_field_u32(sf("sfSequence"), 42);
        o.set_field_u32(sf("sfFlags"), 0);
        o.set_account_id(sf("sfAccount"), acct(0x11));
        o
    };
    assert_eq!(
        make().get_serializer().data(),
        make().get_serializer().data()
    );
}

