// Object with many fields
#[test]
fn so2_many_fields() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u16(sf("sfLedgerEntryType"), 0x0061);
    o.set_field_u32(sf("sfFlags"), 0x00010000);
    o.set_field_u32(sf("sfSequence"), 100);
    o.set_field_u32(sf("sfOwnerCount"), 5);
    o.set_account_id(sf("sfAccount"), acct(0x11));
    o.set_field_amount(sf("sfBalance"), xrp(10_000_000_000));
    o.set_field_h256(sf("sfPreviousTxnID"), Uint256::from_array([0xCC; 32]));
    o.set_field_u32(sf("sfPreviousTxnLgrSeq"), 50);
    o.set_field_vl(sf("sfDomain"), b"ripple.com");
    assert!(o.get_count() >= 9);
    assert!(o.get_serializer().size() > 50);
}

// Verify field order doesn't matter for equality
#[test]
fn so2_field_order_irrelevant() {
    let mut o1 = protocol::STObject::new(sf("sfLedgerEntry"));
    o1.set_field_u32(sf("sfSequence"), 1);
    o1.set_field_u32(sf("sfFlags"), 2);
    let mut o2 = protocol::STObject::new(sf("sfLedgerEntry"));
    o2.set_field_u32(sf("sfFlags"), 2);
    o2.set_field_u32(sf("sfSequence"), 1);
    assert_eq!(
        o1.get_field_u32(sf("sfSequence")),
        o2.get_field_u32(sf("sfSequence"))
    );
    assert_eq!(
        o1.get_field_u32(sf("sfFlags")),
        o2.get_field_u32(sf("sfFlags"))
    );
}

// STTx with optional fields
#[test]
fn so2_sttx_with_memos() {
    let tx = STTx::new(TxType::PAYMENT, |tx| {
        tx.set_account_id(sf("sfAccount"), acct(0x11));
        tx.set_account_id(sf("sfDestination"), acct(0x22));
        tx.set_field_u32(sf("sfSequence"), 1);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_amount(sf("sfAmount"), xrp(1000));
        tx.set_field_u32(sf("sfDestinationTag"), 42);
    });
    assert!(tx.is_field_present(sf("sfDestinationTag")));
    assert_eq!(tx.get_field_u32(sf("sfDestinationTag")), 42);
}
#[test]
fn so2_sttx_without_optional() {
    let tx = STTx::new(TxType::PAYMENT, |tx| {
        tx.set_account_id(sf("sfAccount"), acct(0x11));
        tx.set_account_id(sf("sfDestination"), acct(0x22));
        tx.set_field_u32(sf("sfSequence"), 1);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_amount(sf("sfAmount"), xrp(1000));
    });
    assert!(!tx.is_field_present(sf("sfDestinationTag")));
}

// Object get_count grows
#[test]
fn so2_count_grows() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    let c0 = o.get_count();
    o.set_field_u32(sf("sfSequence"), 1);
    let c1 = o.get_count();
    o.set_field_u32(sf("sfFlags"), 0);
    let c2 = o.get_count();
    assert!(c1 > c0);
    assert!(c2 > c1);
}

// VL binary data preserved exactly
#[test]
fn so2_vl_binary_exact() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    let data: Vec<u8> = (0..=255).collect();
    o.set_field_vl(sf("sfDomain"), &data);
    let got = o.get_field_vl(sf("sfDomain"));
    assert_eq!(got, data);
}

