// ceilIn 1:2 ratio (from C++)
#[test]
fn q_ceil_in_1to2_no_limit() {
    let q =
        protocol::Quality::from_amounts(&protocol::Amounts::new(xrp(1_000_000), xrp(2_000_000)));
    let r = q.ceil_in(
        &protocol::Amounts::new(xrp(40_000_000), xrp(80_000_000)),
        &xrp(40_000_000),
    );
    assert_eq!(r.r#in.xrp().drops(), 40_000_000);
    assert_eq!(r.out.xrp().drops(), 80_000_000);
}
#[test]
fn q_ceil_in_1to2_limit() {
    let q =
        protocol::Quality::from_amounts(&protocol::Amounts::new(xrp(1_000_000), xrp(2_000_000)));
    let r = q.ceil_in(
        &protocol::Amounts::new(xrp(40_000_000), xrp(80_000_000)),
        &xrp(20_000_000),
    );
    assert_eq!(r.r#in.xrp().drops(), 20_000_000);
    assert_eq!(r.out.xrp().drops(), 40_000_000);
}
