// Quality composition (from C++ testComposition)
#[test]
fn q_compose_12_21_eq_11() {
    let q12 = protocol::Quality::from_amounts(&protocol::Amounts::new(
        xrp(231_000_000),
        xrp(462_000_000),
    ));
    let q21 = protocol::Quality::from_amounts(&protocol::Amounts::new(
        xrp(462_000_000),
        xrp(231_000_000),
    ));
    let q11 = protocol::Quality::from_amounts(&protocol::Amounts::new(
        xrp(231_000_000),
        xrp(231_000_000),
    ));
    assert_eq!(protocol::composed_quality(q12, q21), q11);
}
#[test]
fn q_compose_symmetric() {
    let q13 = protocol::Quality::from_amounts(&protocol::Amounts::new(
        xrp(231_000_000),
        xrp(924_000_000),
    ));
    let q31 = protocol::Quality::from_amounts(&protocol::Amounts::new(
        xrp(924_000_000),
        xrp(231_000_000),
    ));
    assert_eq!(
        protocol::composed_quality(q13, q31),
        protocol::composed_quality(q31, q13)
    );
}
#[test]
fn q_compose_13_31_eq_11() {
    let q13 = protocol::Quality::from_amounts(&protocol::Amounts::new(
        xrp(231_000_000),
        xrp(924_000_000),
    ));
    let q31 = protocol::Quality::from_amounts(&protocol::Amounts::new(
        xrp(924_000_000),
        xrp(231_000_000),
    ));
    let q11 = protocol::Quality::from_amounts(&protocol::Amounts::new(
        xrp(231_000_000),
        xrp(231_000_000),
    ));
    assert_eq!(protocol::composed_quality(q13, q31), q11);
}

