// Quality increment/decrement ordering
#[test]
fn q_inc_gt_original() {
    let q =
        protocol::Quality::from_amounts(&protocol::Amounts::new(xrp(1_000_000), xrp(1_000_000)));
    let mut qi = q.clone();
    qi.increment();
    assert!(qi > q);
}
#[test]
fn q_dec_lt_original() {
    let q =
        protocol::Quality::from_amounts(&protocol::Amounts::new(xrp(1_000_000), xrp(1_000_000)));
    let mut qd = q.clone();
    qd.decrement();
    assert!(qd < q);
}

