fn api_for_all_versions() {
    let mut count = 0u32;
    protocol::for_all_api_versions(|_v| {
        count += 1;
    });
    assert!(count >= 2);
}

// STParsedJSON
#[test]
fn spj_empty_object() {
    let json = protocol::JsonValue::Object(Default::default());
    let result = protocol::STParsedJSONObject::new("tx_json", &json);
    let _ = result;
    assert!(true);
}

