// Seed generation from passphrase (from C++ Seed_test)
#[test]
fn seed_master() {
    let s = protocol::generate_seed("masterpassphrase");
    let b58 = protocol::seed::to_base58(&s);
    assert_eq!(b58, "snoPBrXtMeMyMHUVTgbuqAfg1SUTb");
}
#[test]
fn seed_nonrandom() {
    let s = protocol::generate_seed("Non-Random Passphrase");
    let b58 = protocol::seed::to_base58(&s);
    assert_eq!(b58, "snMKnVku798EnBwUfxeSD8953sLYA");
}
#[test]
fn seed_cookies() {
    let s = protocol::generate_seed("cookies excitement hand public");
    let b58 = protocol::seed::to_base58(&s);
    assert_eq!(b58, "sspUXGrmjQhq6mgc24jiRuevZiwKT");
}
#[test]
fn seed_deterministic() {
    let s1 = protocol::generate_seed("test");
    let s2 = protocol::generate_seed("test");
    assert_eq!(s1, s2);
}
#[test]
fn seed_different_passphrases() {
    let s1 = protocol::generate_seed("alice");
    let s2 = protocol::generate_seed("bob");
    assert_ne!(s1, s2);
}
#[test]
fn seed_base58_roundtrip() {
    let s = protocol::generate_seed("masterpassphrase");
    let b58 = protocol::seed::to_base58(&s);
    let s2 = protocol::parse_base58_seed(&b58);
    assert!(s2.is_some());
    assert_eq!(s, s2.unwrap());
}
#[test]
fn seed_parse_valid_1() {
    assert!(protocol::parse_base58_seed("snoPBrXtMeMyMHUVTgbuqAfg1SUTb").is_some());
}
#[test]
fn seed_parse_valid_2() {
    assert!(protocol::parse_base58_seed("snMKnVku798EnBwUfxeSD8953sLYA").is_some());
}
#[test]
fn seed_parse_valid_3() {
    assert!(protocol::parse_base58_seed("sspUXGrmjQhq6mgc24jiRuevZiwKT").is_some());
}
#[test]
fn seed_parse_empty() {
    assert!(protocol::parse_base58_seed("").is_none());
}
#[test]
fn seed_parse_short() {
    assert!(protocol::parse_base58_seed("snoPBrXtMeMyMHUVTgbuqAfg1SUT").is_none());
}
#[test]
fn seed_parse_long() {
    assert!(protocol::parse_base58_seed("snoPBrXtMeMyMHUVTgbuqAfg1SUTbb").is_none());
}
#[test]
fn seed_parse_invalid_char() {
    assert!(protocol::parse_base58_seed("ssp/XGrmjQhq6mgc24jiRuevZiwKT").is_none());
}

// Key generation secp256k1
#[test]
fn key_secp_from_seed() {
    let seed = protocol::generate_seed("key_test");
    let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
    assert_eq!(pk.as_bytes().len(), 33);
}
#[test]
fn key_secp_compressed_prefix() {
    let seed = protocol::generate_seed("prefix_test");
    let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
    assert!(pk.as_bytes()[0] == 0x02 || pk.as_bytes()[0] == 0x03);
}
#[test]
fn key_secp_deterministic() {
    let seed = protocol::generate_seed("det_test");
    let sk1 = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &seed).unwrap();
    let sk2 = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &seed).unwrap();
    assert_eq!(sk1.as_bytes(), sk2.as_bytes());
}
#[test]
fn key_secp_diff_seed_diff_key() {
    let s1 = protocol::generate_seed("seed1");
    let s2 = protocol::generate_seed("seed2");
    let sk1 = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &s1).unwrap();
    let sk2 = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &s2).unwrap();
    assert_ne!(sk1.as_bytes(), sk2.as_bytes());
}

// Key generation ed25519
