// Signing and verification
#[test]
fn sign_secp_nonempty() {
    let seed = protocol::generate_seed("sign_s");
    let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
    let sig = protocol::sign(&pk, &sk, b"hello").unwrap();
    assert!(!sig.is_empty());
}
#[test]
fn sign_ed25519_nonempty() {
    let seed = protocol::generate_seed("sign_e");
    let sk = protocol::generate_secret_key(protocol::KeyType::Ed25519, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Ed25519, &sk).unwrap();
    let sig = protocol::sign(&pk, &sk, b"hello").unwrap();
    assert!(!sig.is_empty());
}
#[test]
fn sign_diff_msg_diff_sig() {
    let seed = protocol::generate_seed("diff_msg");
    let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
    let s1 = protocol::sign(&pk, &sk, b"msg1").unwrap();
    let s2 = protocol::sign(&pk, &sk, b"msg2").unwrap();
    assert_ne!(s1, s2);
}

// AccountID from public key
#[test]
fn acctid_from_secp() {
    let seed = protocol::generate_seed("acct_s");
    let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
    let id = protocol::calc_account_id(pk.as_bytes());
    assert!(!id.data().iter().all(|&b| b == 0));
}
#[test]
fn acctid_from_ed25519() {
    let seed = protocol::generate_seed("acct_e");
    let sk = protocol::generate_secret_key(protocol::KeyType::Ed25519, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Ed25519, &sk).unwrap();
    let id = protocol::calc_account_id(pk.as_bytes());
    assert!(!id.data().iter().all(|&b| b == 0));
}
#[test]
fn acctid_deterministic() {
    let seed = protocol::generate_seed("det_acct");
    let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
    let id1 = protocol::calc_account_id(pk.as_bytes());
    let id2 = protocol::calc_account_id(pk.as_bytes());
    assert_eq!(id1, id2);
}
#[test]
fn acctid_diff_keys_diff_id() {
    let s1 = protocol::generate_seed("k1");
    let s2 = protocol::generate_seed("k2");
    let sk1 = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &s1).unwrap();
    let sk2 = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &s2).unwrap();
    let pk1 = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk1).unwrap();
    let pk2 = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk2).unwrap();
    assert_ne!(
        protocol::calc_account_id(pk1.as_bytes()),
        protocol::calc_account_id(pk2.as_bytes())
    );
}

