// Issue with various currencies
#[test]
fn issue_3char_currencies() {
    for c in [
        "USD", "EUR", "GBP", "JPY", "CHF", "CAD", "AUD", "NZD", "CNY", "INR", "BRL", "KRW",
    ] {
        let cur = protocol::currency_from_string(c);
        let i = Issue::new(cur, acct(0x33));
        assert!(!i.native());
        assert_eq!(i.currency, cur);
    }
}
