fn issue_same_currency_eq() {
    let u1 = protocol::currency_from_string("USD");
    let u2 = protocol::currency_from_string("USD");
    assert_eq!(Issue::new(u1, acct(0x33)), Issue::new(u2, acct(0x33)));
}

