// STObject - more serialization consistency
#[test]
fn rem_obj_ser_order_independent() {
    let mut o1 = protocol::STObject::new(sf("sfLedgerEntry"));
    o1.set_field_u32(sf("sfSequence"), 1);
    o1.set_field_u32(sf("sfFlags"), 2);
    o1.set_account_id(sf("sfAccount"), acct(0x11));
    let mut o2 = protocol::STObject::new(sf("sfLedgerEntry"));
    o2.set_account_id(sf("sfAccount"), acct(0x11));
    o2.set_field_u32(sf("sfFlags"), 2);
    o2.set_field_u32(sf("sfSequence"), 1);
    assert_eq!(
        o1.get_field_u32(sf("sfSequence")),
        o2.get_field_u32(sf("sfSequence"))
    );
}
#[test]
fn rem_obj_ser_u32_bytes() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u32(sf("sfSequence"), 0x12345678);
    let d = o.get_serializer().data().to_vec();
    assert!(d.contains(&0x12));
}
#[test]
fn rem_obj_ser_empty_vl() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_vl(sf("sfDomain"), b"");
    let s = o.get_serializer();
    assert!(s.size() > 0);
}
#[test]
fn rem_obj_ser_large_obj() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    for _ in 0..10 {
        o.set_field_u32(sf("sfSequence"), 42);
    }
    let s = o.get_serializer();
    assert!(s.size() >= 5);
}

