// Issue - hash consistency
#[test]
fn rem_issue_hash_same() {
    use std::collections::HashSet;
    let mut s = HashSet::new();
    let i = Issue::new(usd_currency(), acct(0x33));
    s.insert(i);
    s.insert(i);
    assert_eq!(s.len(), 1);
}
#[test]
fn rem_issue_hash_diff() {
    use std::collections::HashSet;
    let mut s = HashSet::new();
    s.insert(Issue::new(usd_currency(), acct(0x33)));
    s.insert(Issue::new(eur_currency(), acct(0x33)));
    assert_eq!(s.len(), 2);
}
#[test]
fn rem_issue_set_insert_remove() {
    use std::collections::HashSet;
    let mut s = HashSet::new();
    let i1 = Issue::new(usd_currency(), acct(0x11));
    let i2 = Issue::new(eur_currency(), acct(0x22));
    s.insert(i1);
    s.insert(i2);
    assert_eq!(s.len(), 2);
    s.remove(&i1);
    assert_eq!(s.len(), 1);
    s.remove(&i2);
    assert!(s.is_empty());
}
#[test]
fn rem_issue_map_insert() {
    use std::collections::HashMap;
    let mut m = HashMap::new();
    let i1 = Issue::new(usd_currency(), acct(0x11));
    let i2 = Issue::new(eur_currency(), acct(0x22));
    m.insert(i1, 1);
    m.insert(i2, 2);
    assert_eq!(m.len(), 2);
    assert_eq!(m[&i1], 1);
    assert_eq!(m[&i2], 2);
}

