// MultiApiJson
#[test]
fn maj_new() {
    let json = serde_json::json!({});
    let jv = protocol::JsonValue::from(json);
    let maj = protocol::MultiApiJson::<
        { protocol::API_MINIMUM_SUPPORTED_VERSION },
        { protocol::API_MAXIMUM_SUPPORTED_VERSION },
    >::new(jv);
    assert_eq!(
        maj.values().len(),
        (protocol::API_MAXIMUM_SUPPORTED_VERSION - protocol::API_MINIMUM_SUPPORTED_VERSION + 1)
            as usize
    );
}
#[test]
fn maj_set_key() {
    let json = serde_json::json!({});
    let jv = protocol::JsonValue::from(json);
    let mut maj = protocol::MultiApiJson::<
        { protocol::API_MINIMUM_SUPPORTED_VERSION },
        { protocol::API_MAXIMUM_SUPPORTED_VERSION },
    >::new(jv);
    maj.set("test", "value");
    maj.visit(protocol::API_MINIMUM_SUPPORTED_VERSION, |j| {
        assert!(j.get("test").is_some());
    });
}

// STNumber arithmetic
#[test]
fn stn2_zero_is_default() {
    let n = protocol::STNumber::new(basics::number::NumberParts::zero());
    assert!(n.is_default());
}
#[test]
fn stn2_from_1() {
    let n = protocol::STNumber::new(basics::number::NumberParts::from_i64(1));
    assert!(!n.is_default());
    assert_eq!(n.get_text(), "1");
}
#[test]
fn stn2_from_neg1() {
    let n = protocol::STNumber::new(basics::number::NumberParts::from_i64(-1));
    assert!(!n.is_default());
    assert_eq!(n.get_text(), "-1");
}
#[test]
fn stn2_from_100() {
    let n = protocol::STNumber::new(basics::number::NumberParts::from_i64(100));
    assert_eq!(n.get_text(), "100");
}
#[test]
fn stn2_from_neg100() {
    let n = protocol::STNumber::new(basics::number::NumberParts::from_i64(-100));
    assert_eq!(n.get_text(), "-100");
}
#[test]
fn stn2_from_1000000() {
    let n = protocol::STNumber::new(basics::number::NumberParts::from_i64(1000000));
    assert_eq!(n.get_text(), "1000000");
}
#[test]
fn stn2_from_max_i32() {
    let n = protocol::STNumber::new(basics::number::NumberParts::from_i64(i32::MAX as i64));
    assert!(!n.is_default());
}
#[test]
fn stn2_from_min_i32() {
    let n = protocol::STNumber::new(basics::number::NumberParts::from_i64(i32::MIN as i64));
    assert!(!n.is_default());
}
#[test]
fn stn2_set_value() {
    let mut n = protocol::STNumber::new(basics::number::NumberParts::zero());
    assert!(n.is_default());
    n.set_value(basics::number::NumberParts::from_i64(42));
    assert!(!n.is_default());
}
#[test]
fn stn2_value_roundtrip() {
    let v = basics::number::NumberParts::from_i64(999);
    let n = protocol::STNumber::new(v);
    assert_eq!(n.value(), v);
}

// parts_from_string
#[test]
fn stn2_parse_0() {
    let p = protocol::parts_from_string("0").unwrap();
    assert!(p.mantissa == 0);
}
#[test]
fn stn2_parse_1() {
    let p = protocol::parts_from_string("1").unwrap();
    assert!(p.mantissa > 0 && !p.negative);
}
#[test]
fn stn2_parse_neg1() {
    let p = protocol::parts_from_string("-1").unwrap();
    assert!(p.mantissa > 0 && p.negative);
}
#[test]
fn stn2_parse_100() {
    let p = protocol::parts_from_string("100").unwrap();
    assert!(p.mantissa > 0 && !p.negative);
}
#[test]
fn stn2_parse_invalid_empty() {
    assert!(protocol::parts_from_string("").is_err());
}
#[test]
fn stn2_parse_invalid_e() {
    assert!(protocol::parts_from_string("e").is_err());
}
#[test]
fn stn2_parse_invalid_1e() {
    assert!(protocol::parts_from_string("1e").is_err());
}
#[test]
fn stn2_parse_invalid_dot1() {
    assert!(protocol::parts_from_string(".1").is_err());
}
#[test]
fn stn2_parse_invalid_1dot() {
    assert!(protocol::parts_from_string("1.").is_err());
}
#[test]
fn stn2_parse_3_14e2() {
    let p = protocol::parts_from_string("3.14e2");
    assert!(p.is_ok());
}

// PublicKey validation
#[test]
fn pk_secp_33_bytes() {
    let seed = protocol::generate_seed("pk_test");
    let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
    assert_eq!(pk.as_bytes().len(), 33);
}
#[test]
fn pk_ed_33_bytes() {
    let seed = protocol::generate_seed("pk_ed");
    let sk = protocol::generate_secret_key(protocol::KeyType::Ed25519, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Ed25519, &sk).unwrap();
    assert_eq!(pk.as_bytes().len(), 33);
}
#[test]
fn pk_secp_prefix_02_or_03() {
    let seed = protocol::generate_seed("pk_prefix");
    let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
    assert!(pk.as_bytes()[0] == 0x02 || pk.as_bytes()[0] == 0x03);
}
#[test]
fn pk_ed_prefix_ed() {
    let seed = protocol::generate_seed("pk_ed_prefix");
    let sk = protocol::generate_secret_key(protocol::KeyType::Ed25519, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Ed25519, &sk).unwrap();
    assert_eq!(pk.as_bytes()[0], 0xED);
}
#[test]
fn pk_from_slice_valid_secp() {
    let seed = protocol::generate_seed("pk_slice");
    let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
    let pk2 = protocol::PublicKey::from_slice(pk.as_bytes());
    assert!(pk2.is_ok());
}
#[test]
fn pk_from_slice_invalid_short() {
    let pk = protocol::PublicKey::from_slice(&[0x02; 10]);
    assert!(pk.is_err());
}
#[test]
fn pk_from_slice_invalid_empty() {
    let pk = protocol::PublicKey::from_slice(&[]);
    assert!(pk.is_err());
}
#[test]
fn pk_different_seeds_different_keys() {
    let s1 = protocol::generate_seed("pk1");
    let s2 = protocol::generate_seed("pk2");
    let sk1 = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &s1).unwrap();
    let sk2 = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &s2).unwrap();
    let pk1 = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk1).unwrap();
    let pk2 = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk2).unwrap();
    assert_ne!(pk1.as_bytes(), pk2.as_bytes());
}
#[test]
fn pk_same_seed_same_key() {
    let s = protocol::generate_seed("pk_same");
    let sk1 = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &s).unwrap();
    let sk2 = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &s).unwrap();
    let pk1 = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk1).unwrap();
    let pk2 = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk2).unwrap();
    assert_eq!(pk1.as_bytes(), pk2.as_bytes());
}
#[test]
fn pk_to_hex() {
    let seed = protocol::generate_seed("pk_hex");
    let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
    let hex = pk.to_hex();
    assert_eq!(hex.len(), 66);
}

