// STInteger (u8/u16/u32/u64 field serialization via STObject)
#[test]
fn sti_u32_zero() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u32(sf("sfSequence"), 0);
    assert_eq!(o.get_field_u32(sf("sfSequence")), 0);
}
#[test]
fn sti_u32_one() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u32(sf("sfSequence"), 1);
    assert_eq!(o.get_field_u32(sf("sfSequence")), 1);
}
#[test]
fn sti_u32_max() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u32(sf("sfSequence"), u32::MAX);
    assert_eq!(o.get_field_u32(sf("sfSequence")), u32::MAX);
}
#[test]
fn sti_u32_powers() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    for p in [1u32, 10, 100, 1000, 10000, 100000, 1000000] {
        o.set_field_u32(sf("sfSequence"), p);
        assert_eq!(o.get_field_u32(sf("sfSequence")), p);
    }
}
