// SOTemplate-like behavior (required fields present after construction)
#[test]
fn sot_sttx_has_type() {
    let tx = STTx::new(TxType::PAYMENT, |tx| {
        tx.set_account_id(sf("sfAccount"), acct(0x11));
        tx.set_field_u32(sf("sfSequence"), 1);
        tx.set_field_amount(sf("sfFee"), xrp(10));
    });
    assert!(tx.is_field_present(sf("sfAccount")));
    assert!(tx.is_field_present(sf("sfSequence")));
}
#[test]
fn sot_sttx_optional_absent() {
    let tx = STTx::new(TxType::PAYMENT, |tx| {
        tx.set_account_id(sf("sfAccount"), acct(0x11));
        tx.set_field_u32(sf("sfSequence"), 1);
        tx.set_field_amount(sf("sfFee"), xrp(10));
    });
    assert!(!tx.is_field_present(sf("sfExpiration")));
}
#[test]
fn sot_sle_has_key() {
    let k = protocol::account_keylet(acct_id(acct(0x11)));
    let sle = STLedgerEntry::new(k.clone());
    assert_eq!(*sle.key(), k.key);
}

