// More PublicKey tests
#[test]
fn pk2_10_different_seeds() {
    let pks: Vec<_> = (0..10)
        .map(|i| {
            let s = protocol::generate_seed(&format!("seed_{}", i));
            let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &s).unwrap();
            protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap()
        })
        .collect();
    for i in 0..pks.len() {
        for j in (i + 1)..pks.len() {
            assert_ne!(pks[i].as_bytes(), pks[j].as_bytes());
        }
    }
}
#[test]
fn pk2_ed_10_different() {
    let pks: Vec<_> = (0..10)
        .map(|i| {
            let s = protocol::generate_seed(&format!("ed_seed_{}", i));
            let sk = protocol::generate_secret_key(protocol::KeyType::Ed25519, &s).unwrap();
            protocol::derive_public_key(protocol::KeyType::Ed25519, &sk).unwrap()
        })
        .collect();
    for i in 0..pks.len() {
        for j in (i + 1)..pks.len() {
            assert_ne!(pks[i].as_bytes(), pks[j].as_bytes());
        }
    }
}
#[test]
fn pk2_secp_ne_ed_same_seed() {
    let s = protocol::generate_seed("both_key_types");
    let sk_s = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &s).unwrap();
    let sk_e = protocol::generate_secret_key(protocol::KeyType::Ed25519, &s).unwrap();
    let pk_s = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk_s).unwrap();
    let pk_e = protocol::derive_public_key(protocol::KeyType::Ed25519, &sk_e).unwrap();
    assert_ne!(pk_s.as_bytes(), pk_e.as_bytes());
}

