// Sign and verify with multiple messages
#[test]
fn sign2_multiple_msgs() {
    let s = protocol::generate_seed("multi_sign");
    let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &s).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
    let msgs = [
        b"msg1".as_slice(),
        b"msg2",
        b"msg3",
        b"",
        b"longer message here",
    ];
    let sigs: Vec<_> = msgs
        .iter()
        .map(|m| protocol::sign(&pk, &sk, m).unwrap())
        .collect();
    for i in 0..sigs.len() {
        for j in (i + 1)..sigs.len() {
            if msgs[i] != msgs[j] {
                assert_ne!(sigs[i], sigs[j]);
            }
        }
    }
}
#[test]
fn sign2_ed25519_multiple() {
    let s = protocol::generate_seed("ed_multi");
    let sk = protocol::generate_secret_key(protocol::KeyType::Ed25519, &s).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Ed25519, &sk).unwrap();
    let s1 = protocol::sign(&pk, &sk, b"hello").unwrap();
    let s2 = protocol::sign(&pk, &sk, b"world").unwrap();
    assert_ne!(s1, s2);
}

// AccountID from different key types
#[test]
fn acctid2_secp_ne_ed() {
    let seed = protocol::generate_seed("acct_types");
    let sk_s = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &seed).unwrap();
    let sk_e = protocol::generate_secret_key(protocol::KeyType::Ed25519, &seed).unwrap();
    let pk_s = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk_s).unwrap();
    let pk_e = protocol::derive_public_key(protocol::KeyType::Ed25519, &sk_e).unwrap();
    let id_s = protocol::calc_account_id(pk_s.as_bytes());
    let id_e = protocol::calc_account_id(pk_e.as_bytes());
    assert_ne!(id_s, id_e);
}
#[test]
fn acctid2_10_unique() {
    let ids: Vec<_> = (0..10)
        .map(|i| {
            let s = protocol::generate_seed(&format!("acct_{}", i));
            let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &s).unwrap();
            let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
            protocol::calc_account_id(pk.as_bytes())
        })
        .collect();
    for i in 0..ids.len() {
        for j in (i + 1)..ids.len() {
            assert_ne!(ids[i], ids[j]);
        }
    }
}

