// STInteger - u8/u16/u32/u64 comprehensive
#[test]
fn fi_u8_0() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u8(sf("sfCloseResolution"), 0);
    assert_eq!(o.get_field_u8(sf("sfCloseResolution")), 0);
}
#[test]
fn fi_u8_1() {
    let mut o = protocol::STObject::new(sf("sfLedgerEntry"));
    o.set_field_u8(sf("sfCloseResolution"), 1);
    assert_eq!(o.get_field_u8(sf("sfCloseResolution")), 1);
}
