#[test]
fn fk_sign_empty_msg() {
    let s = protocol::generate_seed("empty_msg");
    let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &s).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
    let sig = protocol::sign(&pk, &sk, b"").unwrap();
    assert!(!sig.is_empty());
}
#[test]
fn fk_sign_long_msg() {
    let s = protocol::generate_seed("long_msg");
    let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &s).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
    let msg = vec![0xABu8; 1000];
    let sig = protocol::sign(&pk, &sk, &msg).unwrap();
    assert!(!sig.is_empty());
}
#[test]
fn fk_sign_deterministic() {
    let s = protocol::generate_seed("det_sig");
    let sk = protocol::generate_secret_key(protocol::KeyType::Ed25519, &s).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Ed25519, &sk).unwrap();
    let s1 = protocol::sign(&pk, &sk, b"test").unwrap();
    let s2 = protocol::sign(&pk, &sk, b"test").unwrap();
    assert_eq!(s1, s2);
}

