#[test]
fn fm_values_count() {
    let jv = protocol::JsonValue::from(serde_json::json!({}));
    let maj = protocol::MultiApiJson::<
        { protocol::API_MINIMUM_SUPPORTED_VERSION },
        { protocol::API_MAXIMUM_SUPPORTED_VERSION },
    >::new(jv);
    assert_eq!(
        maj.values().len(),
        (protocol::API_MAXIMUM_SUPPORTED_VERSION - protocol::API_MINIMUM_SUPPORTED_VERSION + 1)
            as usize
    );
}
#[test]
fn fm_set_all_versions() {
    let jv = protocol::JsonValue::from(serde_json::json!({}));
    let mut maj = protocol::MultiApiJson::<
        { protocol::API_MINIMUM_SUPPORTED_VERSION },
        { protocol::API_MAXIMUM_SUPPORTED_VERSION },
    >::new(jv);
    maj.set("key", "val");
    for v in protocol::API_MINIMUM_SUPPORTED_VERSION..=protocol::API_MAXIMUM_SUPPORTED_VERSION {
        maj.visit(v, |j| {
            assert!(j.get("key").is_some());
        });
    }
}
