#[test]
fn ff_amt_mul_iou_large() {
    let gw = acct(0x33);
    let u = usd_currency();
    let asset = protocol::Asset::Issue(Issue::new(u, gw));
    let a = STAmount::from_iou_amount(
        sf_generic(),
        IOUAmount::from_parts(9_999_999_999_999_999, 0).expect("a"),
        Issue::new(u, gw),
    );
    let b = iou(gw, u, 2);
    let r = a.multiply(&b, asset);
    assert!(r.signum() > 0);
}
#[test]
fn ff_amt_div_iou_large() {
    let gw = acct(0x33);
    let u = usd_currency();
    let asset = protocol::Asset::Issue(Issue::new(u, gw));
    let a = STAmount::from_iou_amount(
        sf_generic(),
        IOUAmount::from_parts(9_999_999_999_999_999, 0).expect("a"),
        Issue::new(u, gw),
    );
    let b = iou(gw, u, 2);
    let r = a.divide(&b, asset);
    assert!(r.signum() > 0);
}
#[test]
fn ff_amt_negate_xrp() {
    let mut a = xrp(100);
    a.negate();
    assert_eq!(a.signum(), -1);
    a.negate();
    assert_eq!(a.signum(), 1);
}
#[test]
fn ff_amt_negate_iou() {
    let gw = acct(0x33);
    let u = usd_currency();
    let mut a = iou(gw, u, 100);
    a.negate();
    assert!(a.negative());
    a.negate();
    assert!(!a.negative());
}

// MultiApiJson - visit_mut
#[test]
fn ff_maj_visit_mut() {
    let jv = protocol::JsonValue::from(serde_json::json!({}));
    let mut maj = protocol::MultiApiJson::<
        { protocol::API_MINIMUM_SUPPORTED_VERSION },
        { protocol::API_MAXIMUM_SUPPORTED_VERSION },
    >::new(jv);
    maj.visit_mut(1, |j| {
        if let protocol::JsonValue::Object(m) = j {
            m.insert(
                "added".to_string(),
                protocol::JsonValue::String("yes".to_string()),
            );
        }
    });
    maj.visit(1, |j| {
        assert!(j.get("added").is_some());
    });
}
#[test]
fn ff_maj_independent_versions() {
    let jv = protocol::JsonValue::from(serde_json::json!({}));
    let mut maj = protocol::MultiApiJson::<
        { protocol::API_MINIMUM_SUPPORTED_VERSION },
        { protocol::API_MAXIMUM_SUPPORTED_VERSION },
    >::new(jv);
    maj.visit_mut(1, |j| {
        if let protocol::JsonValue::Object(m) = j {
            m.insert(
                "v1only".to_string(),
                protocol::JsonValue::String("yes".to_string()),
            );
        }
    });
    maj.visit(2, |j| {
        assert!(j.get("v1only").is_none());
    });
}

