// View stacking - payment modifies sender and receiver
#[test]
fn lv4_pay_modifies_both() {
    let a = acct(0x11);
    let b = acct(0x22);
    let l = build_ledger(vec![
        account_root(a, 10_000_000_000, 0, 0),
        account_root(b, 5_000_000_000, 0, 0),
    ]);
    let mut v = new_view(l);
    let tx = STTx::new(TxType::PAYMENT, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_account_id(sf("sfDestination"), b);
        tx.set_field_amount(sf("sfAmount"), xrp(2_000_000_000));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    handle_real_dispatch(&mut v, &tx, TxType::PAYMENT, None);
    let sa = v
        .peek(protocol::account_keylet(acct_id(a)))
        .ok()
        .flatten()
        .unwrap();
    let sb = v
        .peek(protocol::account_keylet(acct_id(b)))
        .ok()
        .flatten()
        .unwrap();
    assert!(sa.get_field_amount(sf("sfBalance")).xrp().drops() < 10_000_000_000);
    assert_eq!(
        sb.get_field_amount(sf("sfBalance")).xrp().drops(),
        7_000_000_000
    );
}
