// AccountID is Uint160-based
#[test]
fn bn_acctid_from_key() {
    let seed = protocol::generate_seed("acct_test");
    let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
    let id = protocol::calc_account_id(pk.as_bytes());
    assert!(!id.data().iter().all(|&b| b == 0));
}
#[test]
fn bn_acctid_deterministic() {
    let seed = protocol::generate_seed("det");
    let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &seed).unwrap();
    let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
    let id1 = protocol::calc_account_id(pk.as_bytes());
    let id2 = protocol::calc_account_id(pk.as_bytes());
    assert_eq!(id1, id2);
}
#[test]
fn bn_acctid_unique_10() {
    let ids: Vec<_> = (0..10)
        .map(|i| {
            let s = protocol::generate_seed(&format!("u{}", i));
            let sk = protocol::generate_secret_key(protocol::KeyType::Secp256k1, &s).unwrap();
            let pk = protocol::derive_public_key(protocol::KeyType::Secp256k1, &sk).unwrap();
            protocol::calc_account_id(pk.as_bytes())
        })
        .collect();
    for i in 0..ids.len() {
        for j in (i + 1)..ids.len() {
            assert_ne!(ids[i], ids[j]);
        }
    }
}

// Serializer (basics)
